194	// ---------- prop builders: what the drones improvise them into ----------
195	function buildPlasmaRing() {
196	  const g = new THREE.Group();
197	  const base = new THREE.Mesh(new THREE.CylinderGeometry(1.2, 1.5, 0.7, 10), SCORCH());
198	  base.position.y = 0.35;
199	  const ring = new THREE.Mesh(
200	    new THREE.TorusGeometry(1.8, 0.3, 12, 36),
201	    new THREE.MeshStandardMaterial({ color: 0x6b4a16, emissive: 0xffb86b, emissiveIntensity: 1.4, roughness: 0.4 })
202	  );
203	  ring.position.y = 3.4;
204	  g.add(base, ring);
205	  g.userData.anim = { type: "ring", ring };
206	  return g;
207	}
208	function buildStarDome() {
209	  const g = new THREE.Group();
210	  const ped = new THREE.Mesh(new THREE.CylinderGeometry(0.9, 1.2, 1.2, 8), SCORCH());
211	  ped.position.y = 0.6;
212	  const stars = new THREE.BufferGeometry();
213	  const pts = new Float32Array(120 * 3);
214	  for (let i = 0; i < 120; i++) {
215	    // random points in a dome above the pedestal
216	    const r = 1.2 + Math.random() * 1.4;
217	    const th = Math.random() * Math.PI * 2;
218	    const ph = Math.random() * Math.PI * 0.5;
219	    pts[i * 3] = Math.cos(th) * Math.sin(ph) * r;
220	    pts[i * 3 + 1] = 3.2 + Math.cos(ph) * r * 0.9;
221	    pts[i * 3 + 2] = Math.sin(th) * Math.sin(ph) * r;
222	  }
223	  stars.setAttribute("position", new THREE.BufferAttribute(pts, 3));
224	  const field = new THREE.Points(stars, new THREE.PointsMaterial({
225	    color: 0xbfe9ff, size: 0.16, transparent: true, opacity: 0.95,
226	    blending: THREE.AdditiveBlending, depthWrite: false,
227	  }));
228	  const orbit = new THREE.Mesh(
229	    new THREE.TorusGeometry(2.0, 0.05, 8, 40),
230	    new THREE.MeshBasicMaterial({ color: 0x6fe3ff, transparent: true, opacity: 0.7 })
231	  );
232	  orbit.position.y = 3.6;
233	  orbit.rotation.x = Math.PI / 2.4;
234	  g.add(ped, field, orbit);
235	  g.userData.anim = { type: "dome", field, orbit };
236	  return g;
237	}
238	function buildSignalSpire(beamTex) {
239	  const g = new THREE.Group();
240	  const spire = new THREE.Mesh(
241	    new THREE.ConeGeometry(0.5, 7.5, 8),
242	    new THREE.MeshStandardMaterial({ color: 0x3a4150, metalness: 0.7, roughness: 0.3, emissive: 0x123a4a, emissiveIntensity: 0.8 })
243	  );
244	  spire.position.y = 3.75;
245	  const beam = new THREE.Mesh(
246	    new THREE.CylinderGeometry(0.4, 0.4, 70, 10, 1, true),
247	    new THREE.MeshBasicMaterial({
248	      map: beamTex, color: 0x9af0ff, transparent: true, opacity: 0.55,
249	      blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide, fog: false,
250	    })
251	  );
252	  beam.position.y = 42;
253	  beam.visible = false;          // fires when the upgrade is ADDED
254	  g.add(spire, beam);
255	  g.userData.anim = { type: "spire", beam };
256	  return g;
257	}
258	function buildGardenPod() {
259	  const g = new THREE.Group();
260	  const tray = new THREE.Mesh(new THREE.CylinderGeometry(1.9, 2.1, 0.6, 12), SCORCH());
261	  tray.position.y = 0.3;
262	  for (let i = 0; i < 5; i++) {
263	    const plant = new THREE.Mesh(
264	      new THREE.ConeGeometry(0.28, 0.9 + (i % 3) * 0.35, 6),
265	      new THREE.MeshStandardMaterial({ color: 0x1d4a2c, emissive: 0x35d97a, emissiveIntensity: 0.7, roughness: 0.7 })
266	    );
267	    const a = (i / 5) * Math.PI * 2;
268	    plant.position.set(Math.cos(a) * 1.0, 1.0, Math.sin(a) * 1.0);
269	    g.add(plant);
270	  }
271	  const domeGlass = new THREE.Mesh(
272	    new THREE.SphereGeometry(2.1, 18, 12, 0, Math.PI * 2, 0, Math.PI / 2),
273	    new THREE.MeshPhysicalMaterial({
274	      color: 0xd8ffe9, metalness: 0, roughness: 0.05, transmission: 0.7,
275	      thickness: 1.2, transparent: true, opacity: 0.4,
276	    })
277	  );
278	  domeGlass.position.y = 0.6;
279	  g.add(tray, domeGlass);
280	  g.userData.anim = { type: "pod" };
281	  return g;
282	}
283	function buildGravSkid() {
284	  const g = new THREE.Group();
285	  const pad = new THREE.Mesh(
286	    new THREE.CylinderGeometry(1.7, 1.9, 0.5, 12),
287	    new THREE.MeshStandardMaterial({ color: 0x2c3140, metalness: 0.6, roughness: 0.35, emissive: 0x123a4a, emissiveIntensity: 0.7 })
288	  );
289	  pad.position.y = 1.6;
290	  const glow = new THREE.Mesh(
291	    new THREE.TorusGeometry(1.5, 0.12, 8, 32),
292	    new THREE.MeshBasicMaterial({ color: 0x6fe3ff, transparent: true, opacity: 0.65 })
293	  );
294	  glow.rotation.x = Math.PI / 2;
295	  glow.position.y = 0.5;
296	  g.add(pad, glow);
297	  g.userData.anim = { type: "skid", pad, glow };
298	  return g;
299	}
