301	// Level 3 places the finished upgrades on its own island (already online —
302	// the questions are about how they got that way). buildSignalSpire takes the
303	// shared beam texture; the rest take no args.
304	export const UPGRADE_BUILDERS = {
305	  buildPlasmaRing, buildStarDome, buildSignalSpire, buildGardenPod, buildGravSkid,
306	};
307	
308	// ---------- the little worker drone ----------
309	function buildDrone() {
310	  const g = new THREE.Group();
311	  const body = new THREE.Mesh(
312	    new THREE.OctahedronGeometry(0.7, 0),
313	    new THREE.MeshStandardMaterial({ color: 0x2c3140, metalness: 0.6, roughness: 0.3, emissive: 0x2a8aa6, emissiveIntensity: 1.0 })
314	  );
315	  const ring = new THREE.Mesh(
316	    new THREE.TorusGeometry(1.0, 0.09, 8, 24),
317	    new THREE.MeshBasicMaterial({ color: 0x6fe3ff, transparent: true, opacity: 0.8 })
318	  );
319	  ring.rotation.x = Math.PI / 2;
320	  g.add(body, ring);
321	  g.userData = { body, ring };
322	  return g;
323	}
324	
325	// The ship console the terminal lives in.
326	function makeConsole() {
327	  const g = new THREE.Group();
328	  const pedestal = new THREE.Mesh(
329	    new THREE.BoxGeometry(2.6, 4.6, 1.6),
330	    new THREE.MeshStandardMaterial({ color: 0x1c2230, metalness: 0.6, roughness: 0.35 })
331	  );
332	  pedestal.position.y = 2.3;
333	  const screen = new THREE.Mesh(
334	    new THREE.PlaneGeometry(2.1, 1.3),
335	    new THREE.MeshStandardMaterial({
336	      color: 0x0c2030, emissive: 0x2a8aa6, emissiveIntensity: 1.4, roughness: 0.3,
337	    })
338	  );
339	  screen.position.set(0, 4.0, 0.82);
340	  screen.rotation.x = -0.28;
341	  g.add(pedestal, screen);
342	  return g;
343	}
344	
345	export function createDroneBayView(renderer, { onExit, onComplete, onNext } = {}) {
346	  const canvas = renderer.domElement;
347	
348	  // ---------- scene & sky ----------
349	  const scene = new THREE.Scene();
350	  scene.background = SKY_CALM.clone();
351	  scene.fog = new THREE.Fog(SKY_CALM.clone(), 90, 320);
352	
353	  const camera = new THREE.PerspectiveCamera(
354	    62, window.innerWidth / window.innerHeight, 0.1, 2000
355	  );
356	
357	  // ---------- lighting ----------
358	  scene.add(new THREE.HemisphereLight(0xcdbcff, 0x3a2f5e, 0.7));
359	  const sun = new THREE.DirectionalLight(SUN_CALM, 1.5);
360	  sun.position.set(60, 90, 40);
361	  scene.add(sun);
362	  scene.add(new THREE.AmbientLight(0x6a5a92, 0.3));
363	
364	  const dome = new THREE.Mesh(
365	    new THREE.SphereGeometry(900, 32, 16),
366	    new THREE.MeshBasicMaterial({ color: DOME_CALM.clone(), side: THREE.BackSide, fog: false })
367	  );
368	  scene.add(dome);
369	
370	  // ---------- terrain (the same island) ----------
371	  const terrain = createTerrain({ size: 200, segments: 220, maxHeight: 26, seed: 1337 });
372	  scene.add(terrain.mesh, terrain.water);
373	
374	  const beamTex = makeBeamTexture();
375	
376	  // ---------- the five work sites ----------
377	  const sites = SYSTEMS.map((sys, idx) => {
378	    const anchor = new THREE.Group();
379	    anchor.position.set(sys.pos.x, terrain.heightAt(sys.pos.x, sys.pos.z), sys.pos.z);
380	
381	    const BUILD = {
382	      buildBrokenCoils, buildBrokenNav, buildBrokenDish, buildBrokenVent, buildBrokenStrut,
383	      buildPlasmaRing, buildStarDome, buildGardenPod, buildGravSkid,
384	      buildSignalSpire: () => buildSignalSpire(beamTex),
385	    };
386	    const brokenModel = BUILD[sys.broken]();
387	    const upgradeModel = BUILD[sys.upgrade]();
388	    upgradeModel.visible = false;
389	    anchor.add(brokenModel, upgradeModel);
390	
391	    // Status beam — readable from across the island:
392	    // amber = broken, cyan pulse = drone at work, ice-blue = sealed (review me).
393	    const beam = new THREE.Mesh(
394	      new THREE.CylinderGeometry(0.6, 0.6, 60, 12, 1, true),
395	      new THREE.MeshBasicMaterial({
396	        map: beamTex, color: 0xff8a5c, transparent: true, opacity: 0.3,
397	        blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide,
398	        fog: false,
399	      })
400	    );
401	    beam.position.y = 30;
402	    anchor.add(beam);
403	
404	    // The checkpoint seal: ice + floating trailer id, like Level 1's bank.
405	    const ice = makeIceBlock();
406	    ice.scale.setScalar(1.25);
407	    ice.position.y = 2.6;
408	    ice.visible = false;
409	    anchor.add(ice);
410	    const sprite = makeIdSprite(sys.ckpt);
411	    sprite.position.y = 8.4;
412	    sprite.visible = false;
413	    anchor.add(sprite);
414	
415	    scene.add(anchor);
416	    return {
417	      sys, idx, anchor, brokenModel, upgradeModel, beam, ice, sprite,
418	      state: "broken",      // broken → working → sealed → added
419	      workT: 0,
420	      meltT: 0,             // ice melt animation after ADD TO SHIP
421	    };
422	  });
423	
424	  // ---------- the drone bay: five parked drones by the console ----------
425	  const drones = SYSTEMS.map((_, i) => {
426	    const d = buildDrone();
427	    const x = BAY_ROW.x0 + i * BAY_ROW.dx;
428	    const home = new THREE.Vector3(x, terrain.heightAt(x, BAY_ROW.z) + 1.2, BAY_ROW.z);
429	    d.position.copy(home);
430	    scene.add(d);
431	    return {
432	      model: d, home,
433	      state: "bay",         // bay → flying → working → returning
434	      site: null,
435	      from: new THREE.Vector3(), to: new THREE.Vector3(),
436	      t: 0, dur: 1,
437	      bobOff: Math.random() * 10,
438	    };
439	  });
440	
441	  // Work beam shown under a working drone (one per drone, toggled).
442	  const workBeams = drones.map(() => {
443	    const m = new THREE.Mesh(
444	      new THREE.CylinderGeometry(0.25, 1.2, 6, 10, 1, true),
445	      new THREE.MeshBasicMaterial({
446	        color: 0x6fe3ff, transparent: true, opacity: 0.5,
447	        blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide,
448	      })
449	    );
450	    m.visible = false;
451	    scene.add(m);
452	    return m;
453	  });
454	
455	  // ---------- the ship console ----------
456	  const consoleAnchor = new THREE.Group();
457	  consoleAnchor.position.set(
458	    CONSOLE_POS.x, terrain.heightAt(CONSOLE_POS.x, CONSOLE_POS.z), CONSOLE_POS.z
459	  );
460	  consoleAnchor.add(makeConsole());
461	  const consoleGlow = new THREE.PointLight(0xffd27a, 5, 28, 2);
462	  consoleGlow.position.y = 5;
463	  consoleAnchor.add(consoleGlow);
464	  scene.add(consoleAnchor);
465	
466	  // ---------- first-person controller ----------
467	  const fp = createFirstPerson(camera, canvas, {
468	    heightAt: terrain.heightAt,
469	    radius: terrain.radius * 0.96,
470	    eyeHeight: 2.6,
471	    speed: 24,
472	  });
473	  scene.add(fp.controls.object);
474	
475	  // Bird's-eye map (M) — see all five beams at once, keep walking meanwhile.
476	  const overhead = createOverhead(scene, terrain, camera);
477	  function setMap(on) {
478	    if (overhead.on === on) return;
479	    overhead.set(on);
480	    fp.setAlwaysMove(on);                       // arrows work without pointer lock
481	    scene.fog.near = on ? 500 : 90;             // don't fog the map out
482	    scene.fog.far = on ? 1400 : 320;
483	    crosshair?.classList.toggle("hidden", on || !fp.isLocked);
484	  }
485	
486	  // ---------- HUD elements (shared FP set + this level's own) ----------
487	  const promptEl = document.getElementById("fp-prompt");
488	  const controlsEl = document.getElementById("fp-controls");
489	  const crosshair = document.getElementById("crosshair");
490	  const tutorialEl = document.getElementById("tutorial");
491	  const fpShared = document.getElementById("fp-shared");
492	  const termEl = document.getElementById("terminal");
493	  const termHint = document.getElementById("term-hint");
494	  const termInput = document.getElementById("term-input");
495	  const termList = document.getElementById("term-list");
496	  const termMsg = document.getElementById("term-msg");
