911	  function onKeyDown(e) {
912	    if (!active) return;
913	
914	    // Briefing is up — Enter/Space begins the run, nothing else.
915	    if (!started) {
916	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
917	      return;
918	    }
919	
920	    // The clock ran out — only R (retry) does anything.
921	    if (failed) {
922	      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
923	      return;
924	    }
925	
926	    // While the terminal is open, all keys feed it.
927	    if (terminalOpen) {
928	      if (e.code === "Escape") { closeTerminal(true); e.preventDefault(); return; }
929	      if (termMode === "review") {
930	        if (!explained && e.code === "Enter") { runExplain(); e.preventDefault(); return; }
931	        if (explained && (e.key === "y" || e.key === "Y")) { addToShip(); e.preventDefault(); return; }
932	        e.preventDefault();
933	        return;
934	      }
935	      // report mode — type the dispatch command (the finish line)
936	      if (reportSent) { e.preventDefault(); return; }  // only Esc closes the report
937	      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
938	      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
939	      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
940	        buffer += e.key;
941	        renderTerminal();
942	        e.preventDefault();
943	      }
944	      return;
945	    }
946	
947	    // Walking around.
948	    // Level cleared → Enter boards the ship; failure never advances (R only).
949	    if (reportSent && e.code === "Enter") { onNext?.(); e.preventDefault(); return; }
950	    if (e.code === "KeyE" && nearSite?.state === "broken") { assignDrone(nearSite); e.preventDefault(); return; }
951	    if (e.code === "KeyM") { setMap(!overhead.on); e.preventDefault(); return; }
952	    if (e.code === "Escape" && fp.isLocked) fp.unlock();
953	    if (e.code === "KeyB") onExit?.();
954	  }
