1023	          s.anchor.position.x + Math.cos(t * 1.4) * 1.2,
1024	          s.anchor.position.y + 6.5 + Math.sin(t * 2.2) * 0.4,
1025	          s.anchor.position.z + Math.sin(t * 1.4) * 1.2
1026	        );
