911	  function onKeyDown(e) {
912	    if (!active) return;
913	
914	    // Briefing is up — Enter/Space begins the run, nothing else.
915	    if (!started) {
916	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
917	      return;
918	    }
919	
920	    // The clock ran out — R retries this level; N returns to the true beginning.
921	    if (failed) {
922	      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
923	      if (e.code === "KeyN") { onNewGame?.(); e.preventDefault(); }
924	      return;
925	    }
926	
927	    // While the terminal is open, all keys feed it.
928	    if (terminalOpen) {
929	      if (e.code === "Escape") { closeTerminal(true); e.preventDefault(); return; }
930	      if (termMode === "review") {
931	        if (!explained && e.code === "Enter") { runExplain(); e.preventDefault(); return; }
932	        if (explained && (e.key === "y" || e.key === "Y")) { addToShip(); e.preventDefault(); return; }
933	        e.preventDefault();
934	        return;
935	      }
936	      // report mode — type the dispatch command (the finish line)
937	      if (reportSent) { e.preventDefault(); return; }  // only Esc closes the report
938	      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
939	      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
940	      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
941	        buffer += e.key;
942	        renderTerminal();
943	        e.preventDefault();
944	      }
945	      return;
946	    }
947	
948	    // Walking around.
949	    // Level cleared → Enter boards the ship; failure never advances (R only).
950	    if (reportSent && e.code === "Enter") { onNext?.(); e.preventDefault(); return; }
951	    if (e.code === "KeyE" && nearSite?.state === "broken") { assignDrone(nearSite); e.preventDefault(); return; }
952	    if (e.code === "KeyM") { setMap(!overhead.on); e.preventDefault(); return; }
953	    if (e.code === "Escape" && fp.isLocked) fp.unlock();
954	    if (e.code === "KeyB") onExit?.();
955	  }
