991	  // ---------- per-frame ----------
992	  function update(dt, t) {
993	    fp.update(dt);
994	
995	    // Level countdown — one clock for the whole run.
996	    if (active && timerRunning && !failed && !reportSent) {
997	      timeLeft = Math.max(0, timeLeft - dt);
998	      updateClock();
999	      if (timeLeft <= 0) failLevel();
1000	    }
1001	    applyPanicSky();
1002	
1003	    // Drones fly, work, and head home.
1004	    for (let i = 0; i < drones.length; i++) {
1005	      const d = drones[i];
1006	      const beam = workBeams[i];
1007	      if (d.state === "bay") {
1008	        d.model.position.y = d.home.y + Math.sin((t + d.bobOff) * 2) * 0.15;
1009	        d.model.userData.ring.rotation.z += dt * 1.2;
1010	      } else if (d.state === "flying" || d.state === "returning") {
1011	        d.t += dt;
1012	        const k = Math.min(1, d.t / d.dur);
1013	        const ease = k * k * (3 - 2 * k);
1014	        d.model.position.lerpVectors(d.from, d.to, ease);
1015	        d.model.position.y += Math.sin(k * Math.PI) * 3;   // arc over the island
1016	        d.model.userData.ring.rotation.z += dt * 6;
1017	        if (k >= 1) {
1018	          if (d.state === "flying") d.state = "working";
1019	          else { d.state = "bay"; d.model.position.copy(d.home); }
1020	        }
1021	      } else if (d.state === "working") {
1022	        const s = d.site;
1023	        d.model.position.set(
1024	          s.anchor.position.x + Math.cos(t * 1.4) * 1.2,
1025	          s.anchor.position.y + 6.5 + Math.sin(t * 2.2) * 0.4,
1026	          s.anchor.position.z + Math.sin(t * 1.4) * 1.2
1027	        );
1028	        d.model.userData.ring.rotation.z += dt * 9;
1029	        beam.visible = true;
1030	        beam.position.set(d.model.position.x, d.model.position.y - 3.2, d.model.position.z);
1031	        beam.material.opacity = 0.35 + Math.sin(t * 11) * 0.2;
1032	
1033	        // The actual work happens whether you watch or not.
1034	        if (active && started && !failed) {
1035	          s.workT += dt;
1036	          if (s.workT >= WORK_TIME) {
1037	            sealSite(s);
1038	            beam.visible = false;
1039	            d.state = "returning";
1040	            d.site = null;
1041	            d.from.copy(d.model.position);
1042	            d.to.copy(d.home);
1043	            d.t = 0;
1044	            d.dur = Math.max(1, d.from.distanceTo(d.to) / DRONE_SPEED);
1045	          }
1046	        }
1047	      }
1048	    }
1049	
1050	    // Sites: status beams, warning blinks, seals, and live upgrades.
1051	    for (const s of sites) {
1052	      if (s.state === "broken") {
1053	        s.beam.material.color.setHex(0xff8a5c);
1054	        s.beam.material.opacity = 0.24 + Math.sin(t * 1.6 + s.idx) * 0.08;
1055	        s.beam.visible = true;
1056	        const warn = s.brokenModel.userData.warn;
1057	        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + s.idx) > 0 ? 1.8 : 0.2;
1058	      } else if (s.state === "working") {
1059	        s.beam.material.color.setHex(0x6fe3ff);
1060	        s.beam.material.opacity = 0.4 + Math.sin(t * 6) * 0.18;
1061	        s.beam.visible = true;
1062	      } else if (s.state === "sealed") {
1063	        s.beam.material.color.setHex(0x8fe3ff);
1064	        s.beam.material.opacity = 0.42;
1065	        s.beam.visible = true;
1066	      } else {
1067	        s.beam.visible = false;       // added — the upgrade itself is the landmark
1068	        if (s.meltT > 0) {            // the checkpoint seal melts away
1069	          s.meltT = Math.max(0, s.meltT - dt);
1070	          s.ice.material.opacity = 0.62 * (s.meltT / MELT_DUR);
1071	          if (s.meltT <= 0) s.ice.visible = false;
1072	        }
1073	        // The improvised upgrades live a little.
1074	        const anim = s.upgradeModel.userData.anim;
1075	        if (anim?.type === "ring") {
1076	          anim.ring.rotation.y += dt * 0.8;
1077	          anim.ring.position.y = 3.4 + Math.sin(t * 1.6) * 0.2;
1078	        } else if (anim?.type === "dome") {
1079	          anim.field.rotation.y += dt * 0.25;
1080	          anim.orbit.rotation.z += dt * 0.6;
1081	        } else if (anim?.type === "skid") {
1082	          anim.pad.position.y = 1.6 + Math.sin(t * 1.8) * 0.25;
1083	        }
1084	      }
1085	    }
1086	
1087	    // Proximity: nearest site, and the ship console.
1088	    nearSite = null;
1089	    let nd = Infinity;
1090	    for (const s of sites) {
1091	      const d = Math.hypot(
1092	        camera.position.x - s.anchor.position.x,
1093	        camera.position.z - s.anchor.position.z
1094	      );
1095	      if (d < nd) { nd = d; if (d <= INTERACT_DIST) nearSite = s; }
1096	    }
1097	    nearConsole = Math.hypot(
1098	      camera.position.x - CONSOLE_POS.x, camera.position.z - CONSOLE_POS.z
1099	    ) <= CONSOLE_DIST;
1100	    consoleGlow.intensity = allAdded() && !reportSent ? 8 + Math.sin(t * 4) * 3 : 5;
1101	
1102	    // Terminals open themselves at the right places, like Level 1. After the
1103	    // fifth accept the report prompt is already open in place; if the player
1104	    // wanders off, any ONLINE system (or the bay console) reopens it.
1105	    const atReportSpot = nearConsole || nearSite?.state === "added";
1106	    if (active && started && !failed) {
1107	      if (dismissedSite && nearSite !== dismissedSite) dismissedSite = null;
1108	      if (reportDismissed && !atReportSpot) reportDismissed = false;
1109	      if (!terminalOpen) {
1110	        if (nearSite?.state === "sealed" && nearSite !== dismissedSite) {
1111	          openTerminal("review", nearSite);
1112	        } else if (atReportSpot && allAdded() && !reportSent && !reportDismissed) {
1113	          openTerminal("report", null);
1114	        }
1115	      } else if (termMode === "review" &&
1116	                 (nearSite !== reviewSite || reviewSite.state !== "sealed")) {
1117	        // walked away mid-review (ADD closes it itself)
1118	        if (nearSite !== reviewSite) closeTerminal(false);
1119	      } else if (termMode === "report" && !atReportSpot && !reportSent) {
1120	        closeTerminal(false);
1121	      }
1122	    }
1123	
1124	    overhead.update(t);
1125	    if (active) refreshHud();
1126	  }
1127	
1128	  // ---------- lifecycle ----------
1129	  function enter() {
