import * as THREE from "three";
import { createTerrain } from "./terrain.js";
import { makeBeamTexture, makeIceBlock, makeIdSprite } from "./memoryProps.js";

// LEVEL 2 ("The Drone Bay") — mission control, not a foot race.
//
// The day-to-day agentic loop, played as a starting grid. Five ship systems
// are dark out across the island; five cars (subagents) wait at the bay. You
// don't run — you ORCHESTRATE:
//
//   click a car            → it arms (engine lit)
//   press SPACE            → every armed car launches at once (the green flag)
//   click a car mid-run    → spend a nitro charge, it surges (catch-up tool)
//   a car reaches its system → its work seals under a checkpoint (ice beam)
//   click the parked car   → `entire checkpoint explain <id>` is PRE-FILLED
//   read what it did       → ADD TO SHIP (Y) → system online
//   all five online        → type `entire dispatch` — the day writes itself
//
// Arm one and green-flag at a time = sequential. Arm all five, one green flag
// = parallel — the fast clear. Nothing forces parallel; the clock just rewards
// it. Cars IMPROVISE (a bent dish comes back as a signal spire); the transform
// is what makes you NEED the explanation.

const TOTAL_TIME = 150;      // seconds for the whole run (tunable)
const BASE_SPEED = 1 / 14;   // lane progress per second (un-boosted ≈ 14s)
const BOOST_MULT = 2.6;      // nitro speed multiplier
const BOOST_DUR  = 2.2;      // seconds a nitro surge lasts
const NITRO_MAX  = 3;        // charges per run
const LOW_TIME = 45;         // clock turns urgent under this
const CRIT_TIME = 15;        // clock goes CRITICAL under this
const PANIC_TIME = 45;       // the SKY starts shifting toward panic-red
const MELT_DUR = 1.2;        // seconds the ice takes to melt on ADD TO SHIP

// Starting grid — five parallel lanes fanning slightly out to the systems.
const START_Z = 64;
const FINISH_Z = -34;
const LANE = (i) => ({ startX: (i - 2) * 14, finishX: (i - 2) * 24 });

// Sky panic palette — same dread as Level 1's clock.
const SKY_CALM  = new THREE.Color(0x2a2350);
const SKY_PANIC = new THREE.Color(0x6e0f16);
const FOG_PANIC = new THREE.Color(0x4a0a0e);
const DOME_CALM = new THREE.Color(0x3a3168);
const DOME_PANIC = new THREE.Color(0x7a141c);
const SUN_CALM  = new THREE.Color(0xfff1dc);
const SUN_PANIC = new THREE.Color(0xff5a3c);

// The five dark systems, what the cars improvise them into, and the story each
// checkpoint carries. Ids are fixed so the fiction is stable across runs.
// Exported: Level 3 quizzes the player on this exact record (and uses sys.pos
// on its own island — left untouched here; this level lays out its own grid).
export const SYSTEMS = [
  {
    ckpt: "a1c9e4f72b05", name: "IGNITION COILS",
