    })
  );
  screen.position.set(0, 4.0, 0.82);
  screen.rotation.x = -0.28;
  g.add(pedestal, screen);
  return g;
}

export function createDroneBayView(renderer, { onExit, onComplete, onNext, onNewGame } = {}) {
  const canvas = renderer.domElement;

  // ---------- scene & sky ----------
  const scene = new THREE.Scene();
  scene.background = SKY_CALM.clone();
  scene.fog = new THREE.Fog(SKY_CALM.clone(), 120, 360);

  const camera = new THREE.PerspectiveCamera(
    60, window.innerWidth / window.innerHeight, 0.1, 2000
  );
  // Fixed mission-control vantage: behind the grid, looking out at the systems.
  camera.position.set(0, 32, 104);
  camera.lookAt(0, 2, 4);

  // ---------- lighting ----------
  scene.add(new THREE.HemisphereLight(0xcdbcff, 0x3a2f5e, 0.7));
  const sun = new THREE.DirectionalLight(SUN_CALM, 1.5);
  sun.position.set(60, 90, 40);
  scene.add(sun);
  scene.add(new THREE.AmbientLight(0x6a5a92, 0.3));

  const dome = new THREE.Mesh(
    new THREE.SphereGeometry(900, 32, 16),
    new THREE.MeshBasicMaterial({ color: DOME_CALM.clone(), side: THREE.BackSide, fog: false })
  );
  scene.add(dome);

  // ---------- terrain (the same island) ----------
  const terrain = createTerrain({ size: 200, segments: 220, maxHeight: 26, seed: 1337 });
  scene.add(terrain.mesh, terrain.water);

  const beamTex = makeBeamTexture();

  // ---------- the five lanes: a car at the grid, a system at the finish ----------
  const BUILD = {
    buildBrokenCoils, buildBrokenNav, buildBrokenDish, buildBrokenVent, buildBrokenStrut,
    buildPlasmaRing, buildStarDome, buildGardenPod, buildGravSkid,
    buildSignalSpire: () => buildSignalSpire(beamTex),
  };

  const lanes = SYSTEMS.map((sys, idx) => {
    const { startX, finishX } = LANE(idx);
    const start = new THREE.Vector3(startX, terrain.heightAt(startX, START_Z) + 0.6, START_Z);
    const finish = new THREE.Vector3(finishX, terrain.heightAt(finishX, FINISH_Z), FINISH_Z);

    // The system (finish line).
    const anchor = new THREE.Group();
    anchor.position.copy(finish);
    const brokenModel = BUILD[sys.broken]();
    const upgradeModel = BUILD[sys.upgrade]();
    upgradeModel.visible = false;
    anchor.add(brokenModel, upgradeModel);

    // Status beam: amber = waiting, cyan = car inbound, ice-blue = sealed.
    const beam = new THREE.Mesh(
      new THREE.CylinderGeometry(0.6, 0.6, 60, 12, 1, true),
      new THREE.MeshBasicMaterial({
        map: beamTex, color: 0xff8a5c, transparent: true, opacity: 0.3,
        blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide, fog: false,
      })
    );
    beam.position.y = 30;
    anchor.add(beam);

    // The checkpoint seal: ice + floating trailer id, like Level 1's bank.
    const ice = makeIceBlock();
    ice.scale.setScalar(1.25);
    ice.position.y = 2.6;
    ice.visible = false;
    anchor.add(ice);
    const sprite = makeIdSprite(sys.ckpt);
    sprite.position.y = 8.4;
    sprite.visible = false;
    anchor.add(sprite);
    scene.add(anchor);

    // The rail — two glowing lines sampled along the terrain so they don't clip.
    const railMat = new THREE.LineBasicMaterial({ color: 0x35506a, transparent: true, opacity: 0.6 });
    const railL = new THREE.Line(railGeo(start, finish, -1.2, terrain), railMat);
    const railR = new THREE.Line(railGeo(start, finish, 1.2, terrain), railMat);
    scene.add(railL, railR);

    // The car, parked at the grid.
    const car = buildCar();
    car.position.copy(start);
    car.lookAt(finish.x, start.y, finish.z);
    car.userData.laneIdx = idx;
    scene.add(car);

    return {
      sys, idx, start, finish, anchor, brokenModel, upgradeModel, beam, ice, sprite,
      car, railL, railR, railMat,
      state: "staged",     // staged → running → sealed → added
      armed: false,
      prog: 0,             // 0..1 along the lane
      boostT: 0,           // remaining nitro time
      meltT: 0,            // ice melt after ADD TO SHIP
    };
  });

  function railGeo(a, b, offX, terr) {
    const N = 24;
    const pts = [];
    for (let i = 0; i <= N; i++) {
      const k = i / N;
      const x = a.x + (b.x - a.x) * k + offX;
      const z = a.z + (b.z - a.z) * k;
      pts.push(new THREE.Vector3(x, terr.heightAt(x, z) + 0.25, z));
    }
    return new THREE.BufferGeometry().setFromPoints(pts);
  }

  // ---------- the ship console (behind the grid) ----------
  const consoleAnchor = new THREE.Group();
  const cz = START_Z + 12;
  consoleAnchor.position.set(0, terrain.heightAt(0, cz), cz);
  consoleAnchor.add(makeConsole());
  const consoleGlow = new THREE.PointLight(0xffd27a, 5, 28, 2);
  consoleGlow.position.y = 5;
  consoleAnchor.add(consoleGlow);
  scene.add(consoleAnchor);

  // ---------- spark bursts (nitro / seal juice) ----------
  const sparks = [];
  function spawnSpark(pos, color = 0x9af0ff, n = 14) {
    const arr = new Float32Array(n * 3);
    const vel = [];
    for (let i = 0; i < n; i++) {
      arr[i * 3] = pos.x; arr[i * 3 + 1] = pos.y; arr[i * 3 + 2] = pos.z;
      vel.push(new THREE.Vector3((Math.random() - 0.5) * 9, Math.random() * 7, (Math.random() - 0.5) * 9));
    }
    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(arr, 3));
    const mat = new THREE.PointsMaterial({
      color, size: 0.45, transparent: true, opacity: 1,
      blending: THREE.AdditiveBlending, depthWrite: false,
    });
    const pts = new THREE.Points(geo, mat);
    scene.add(pts);
    sparks.push({ pts, geo, mat, vel, life: 0, ttl: 0.7 });
  }

  // ---------- HUD elements ----------
  const promptEl = document.getElementById("fp-prompt");
  const controlsEl = document.getElementById("fp-controls");
  const crosshair = document.getElementById("crosshair");
  const tutorialEl = document.getElementById("tutorial");
  const fpShared = document.getElementById("fp-shared");
  const termEl = document.getElementById("terminal");
  const termHint = document.getElementById("term-hint");
  const termInput = document.getElementById("term-input");
  const termList = document.getElementById("term-list");
  const termMsg = document.getElementById("term-msg");
  const termCta = document.getElementById("term-cta");
  const dbHud = document.getElementById("db-hud");
  const briefingEl = document.getElementById("db-briefing");
  const briefingStartBtn = document.getElementById("db-briefing-start");
  const countdownEl = document.getElementById("db-countdown");
  const countdownTime = document.getElementById("db-countdown-time");
  const systemsEl = document.getElementById("db-systems-rows");
  const winEl = document.getElementById("db-win");
  const winSub = document.getElementById("db-win-sub");
  const failEl = document.getElementById("db-fail");

  let active = false;
  let started = false;
  let failed = false;
  let reportSent = false;       // `entire dispatch` has been run — the win
  let promptText = null;
  const taught = new Set();
  let tutorialTimer = null;
  let msgTimer = null;
  let winTimer = null;
  let nitro = NITRO_MAX;

  // Level countdown — the single source of pressure for the whole run.
  let timeLeft = TOTAL_TIME;
  let timerRunning = false;

  // Terminal state. Two modes share the one terminal:
  //  "review" — pre-filled `entire checkpoint explain <id>` at a sealed system
  //  "report" — type `entire dispatch` (the finish line)
  let terminalOpen = false;
  let termMode = null;
  let reviewSite = null;        // the sealed lane being reviewed
  let explained = false;        // Enter pressed — the card is showing
  let buffer = "";
  let reportDismissed = false;

  const addedCount = () => lanes.filter((l) => l.state === "added").length;
  const allAdded = () => addedCount() >= lanes.length;

  // ---------- raycasting (the mouse is free — click cars) ----------
  const raycaster = new THREE.Raycaster();
  const ndc = new THREE.Vector2();
  let hoverLane = null;

  function laneAtPointer(e) {
    const rect = canvas.getBoundingClientRect();
    ndc.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
    ndc.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
    raycaster.setFromCamera(ndc, camera);
    const hits = raycaster.intersectObjects(lanes.map((l) => l.car), true);
    if (!hits.length) return null;
    let o = hits[0].object;
    while (o && o.userData.laneIdx === undefined) o = o.parent;
    return o ? lanes[o.userData.laneIdx] : null;
  }

  // ---------- HUD helpers ----------
  function setPrompt(text) {
    if (!promptEl || text === promptText) return;
    promptText = text;
    if (text) { promptEl.textContent = text; promptEl.classList.remove("hidden"); }
    else promptEl.classList.add("hidden");
  }
  function showTutorial(text, ms = 5500) {
    if (!tutorialEl) return;
    clearTimeout(tutorialTimer);
    tutorialEl.textContent = text;
    tutorialEl.classList.remove("hidden");
    if (ms > 0) tutorialTimer = setTimeout(() => tutorialEl.classList.add("hidden"), ms);
  }
  function teachOnce(key, text, ms) {
    if (taught.has(key)) return;
    taught.add(key);
    showTutorial(text, ms);
  }
  function setControls() {
    if (!controlsEl) return;
    controlsEl.innerHTML = `
      <span class="control-item"><span class="control-label">Arm a car</span><span class="key key-wide">click</span></span>
      <span class="control-item"><span class="control-label">Launch armed</span><span class="key">Space</span></span>
      <span class="control-item"><span class="control-label">Nitro a runner</span><span class="key key-wide">click</span></span>
      <span class="control-item"><span class="control-label">Review a finish</span><span class="key key-wide">click</span></span>
      <span class="control-item"><span class="control-label">Return to orbit</span><span class="key">B</span></span>
    `;
    controlsEl.classList.remove("hidden");
  }
  function hideControls() { controlsEl?.classList.add("hidden"); }

  // ---------- systems status panel ----------
  const STATE_LABEL = {
    staged: "STAGED", armed: "ARMED", running: "EN ROUTE", sealed: "READY TO REVIEW", added: "ONLINE",
  };
  function laneClass(l) {
    if (l.state === "staged") return l.armed ? "armed" : "staged";
    return l.state;
  }
  function updateSystems() {
    if (!systemsEl) return;
    const dots = Array.from({ length: NITRO_MAX }, (_, i) =>
      `<span class="db-nitro-dot${i < nitro ? "" : " is-spent"}"></span>`).join("");
    systemsEl.innerHTML =
      `<div class="db-nitro"><span class="db-nitro-label">NITRO</span><span class="db-nitro-dots">${dots}</span></div>` +
      lanes.map((l) => {
        const cls = laneClass(l);
        const label = cls === "staged" && l.armed ? STATE_LABEL.armed : STATE_LABEL[cls === "armed" ? "armed" : l.state];
        return `<div class="db-sys is-${cls}">` +
          `<span class="db-sys-name">${l.sys.name}</span>` +
          `<span class="db-sys-state">${label}</span></div>`;
      }).join("");
  }

  // ---------- level countdown ----------
  function fmtTime(s) {
    s = Math.max(0, Math.ceil(s));
    return `${Math.floor(s / 60)}:${String(s % 60).padStart(2, "0")}`;
  }
  function updateClock() {
    if (countdownTime) countdownTime.textContent = fmtTime(timeLeft);
    countdownEl?.classList.toggle("is-low", timerRunning && timeLeft <= LOW_TIME);
    countdownEl?.classList.toggle("is-critical", timerRunning && timeLeft <= CRIT_TIME);
  }
  function panicFactor() {
    if (failed) return 1;
    if (!timerRunning || timeLeft > PANIC_TIME) return 0;
    let p = (PANIC_TIME - timeLeft) / PANIC_TIME;
    p *= p;
    if (timeLeft <= CRIT_TIME) {
      const throb = 0.5 + 0.5 * Math.sin(performance.now() / 85);
      p += 0.14 * throb;
    }
    return Math.min(1, p);
  }
  function applyPanicSky() {
    const p = reportSent ? 0 : panicFactor();
    scene.background.copy(SKY_CALM).lerp(SKY_PANIC, p);
    scene.fog.color.copy(SKY_CALM).lerp(FOG_PANIC, p);
    dome.material.color.copy(DOME_CALM).lerp(DOME_PANIC, p);
    sun.color.copy(SUN_CALM).lerp(SUN_PANIC, p * 0.85);
  }

  // ---------- briefing / win / fail / reset ----------
  function showBriefing() {
    timerRunning = false;
    tutorialEl?.classList.add("hidden");
    briefingEl?.classList.remove("hidden");
  }
  function startLevel() {
    if (started) return;
    started = true;
    briefingEl?.classList.add("hidden");
    timeLeft = TOTAL_TIME;
    timerRunning = true;
    updateClock();
    updateSystems();
    showTutorial("Click a car to arm it, then press SPACE to launch. Arm all five and launch together — that's the fast clear.", 9000);
  }
  briefingStartBtn?.addEventListener("click", startLevel);

  function failLevel() {
    if (failed || reportSent) return;
    failed = true;
    timerRunning = false;
    closeTerminal(false);
    countdownEl?.classList.remove("is-low", "is-critical");
    tutorialEl?.classList.add("hidden");
    failEl?.classList.remove("hidden");
  }
  function resetLevel() {
    failed = false;
    reportSent = false;
    reportDismissed = false;
    nitro = NITRO_MAX;
    clearTimeout(winTimer);
    for (const l of lanes) {
      l.state = "staged";
      l.armed = false;
      l.prog = 0; l.boostT = 0; l.meltT = 0;
      l.car.position.copy(l.start);
      l.car.lookAt(l.finish.x, l.start.y, l.finish.z);
      l.car.userData.glow.material.opacity = 0;
      l.brokenModel.visible = true;
      l.upgradeModel.visible = false;
      const anim = l.upgradeModel.userData.anim;
      if (anim?.type === "spire") anim.beam.visible = false;
      l.ice.visible = false;
      l.ice.material.opacity = 0.62;
      l.sprite.visible = false;
    }
    failEl?.classList.add("hidden");
    winEl?.classList.add("hidden");
    updateSystems();
    timeLeft = TOTAL_TIME;
    timerRunning = true;
    updateClock();
    showTutorial("New attempt — arm the whole grid and drop one green flag.", 6000);
  }

  // ---------- launch / boost ----------
  function toggleArm(l) {
    if (l.state !== "staged") return;
    l.armed = !l.armed;
    updateSystems();
    if (l.armed) teachOnce("armed", "Armed. Arm more, or press SPACE to send every armed car at once.", 7000);
  }
  function greenFlag() {
    let launched = 0;
    for (const l of lanes) {
      if (l.state === "staged" && l.armed) {
        l.state = "running"; l.armed = false; l.prog = 0; launched++;
      }
    }
    if (!launched) return;
    updateSystems();
    teachOnce("launched", "They're off — and improvising. Nitro a laggard by clicking it; you've got three charges.", 8000);
  }
  function boost(l) {
    if (l.state !== "running") return;
    if (nitro <= 0) { flashTerminalOff("out of nitro"); return; }
    if (l.boostT > 0) return;            // already surging
    nitro -= 1;
    l.boostT = BOOST_DUR;
    spawnSpark(l.car.position.clone(), 0xffb86b, 18);
    updateSystems();
  }
  function flashTerminalOff(text) {
    // a tiny tutorial-line nudge when there's no terminal to flash
    showTutorial(text, 1800);
  }
  function sealSite(l) {
    l.state = "sealed";
    l.brokenModel.visible = false;
    l.upgradeModel.visible = true;       // built — but dormant until ADD TO SHIP
    l.ice.visible = true;
    l.ice.material.opacity = 0.62;
    l.sprite.visible = true;
    l.car.userData.glow.material.opacity = 0;
    spawnSpark(l.anchor.position.clone().setY(l.anchor.position.y + 3), 0x8fe3ff, 16);
    updateSystems();
    teachOnce("sealed",
      "A car finished — its work is sealed under a checkpoint (ice-blue). Click the car to see what it actually did.", 8000);
  }

  // ---------- terminal ----------
  function flashTerminal(text, ok) {
    if (!termMsg) return;
    clearTimeout(msgTimer);
    termMsg.textContent = text;
    termMsg.classList.remove("show-ok", "show-err");
    termMsg.classList.add(ok ? "show-ok" : "show-err");
    msgTimer = setTimeout(() => termMsg.classList.remove("show-ok", "show-err"), 3600);
  }
  function renderTerminal() {
    if (!terminalOpen) return;
    if (termMode === "review") {
      if (!explained) {
        termHint.textContent = "# what did the subagent actually do? ask the checkpoint";
        termInput.textContent = `entire checkpoint explain ${reviewSite.sys.ckpt}`;
        termInput.classList.remove("is-dim");
        if (termCta) termCta.innerHTML =
          `<span class="cta-label">PRESS</span>` +
          `<kbd class="cta-key cta-key-yes">Enter</kbd><span class="cta-note">run it</span>`;
      } else {
        termHint.textContent = "# reviewed — your call";
        termInput.textContent = `entire checkpoint explain ${reviewSite.sys.ckpt}`;
        termInput.classList.add("is-dim");
        if (termCta) termCta.innerHTML =
          `<button id="db-add-btn" type="button">ADD TO SHIP</button>` +
          `<span class="cta-note">or press <kbd class="cta-key cta-key-yes">Y</kbd></span>`;
      }
    } else if (termMode === "report") {
      termHint.textContent = reportSent
        ? "# dispatch sent — the day is on the record"
        : "# five jobs accepted — send the day's report";
      termInput.textContent = buffer;
      termInput.classList.remove("is-dim");
      if (termCta) termCta.innerHTML = reportSent ? "" :
        `<span class="cta-label">TYPE</span><span class="cta-cmd">entire dispatch</span>`;
    }
  }
  function openTerminal(mode, site) {
    if (terminalOpen) return;
    terminalOpen = true;
    termMode = mode;
    reviewSite = site || null;
    explained = false;
    buffer = "";
    termMsg?.classList.remove("show-ok", "show-err");
    termList?.classList.add("hidden");
    termEl?.classList.remove("hidden");
    renderTerminal();
  }
  function closeTerminal(dismiss) {
    if (!terminalOpen) return;
    if (dismiss && termMode === "report") reportDismissed = true;
    terminalOpen = false;
    termMode = null;
    reviewSite = null;
    explained = false;
    buffer = "";
    termEl?.classList.add("hidden");
    termList?.classList.add("hidden");
  }

  // ---------- entire checkpoint explain (pre-filled, Enter to run) ----------
  function runExplain() {
    if (!reviewSite || explained) return;
    explained = true;
    const s = reviewSite;
    if (termList) {
      termList.innerHTML =
        `<div class="term-list-row"><span class="tl-key tl-exp-key">checkpoint</span>` +
        `<span class="tl-title">${s.sys.ckpt}</span></div>` +
        s.sys.card.map(([k, v]) =>
          `<div class="term-list-row"><span class="tl-key tl-exp-key">${k}</span>` +
          `<span class="tl-title">${v}</span></div>`
        ).join("");
      termList.classList.remove("hidden");
    }
    flashTerminal(`explained ${s.sys.ckpt} — ${s.sys.name.toLowerCase()} is now a ${s.sys.became}`, true);
    teachOnce("explained",
      "That's the story behind the checkpoint — work you didn't watch is never a mystery. If it's good, add it to the ship.", 8000);
    renderTerminal();
  }

  // ---------- ADD TO SHIP ----------
  function addToShip() {
    if (!reviewSite || !explained) return;
    const s = reviewSite;
    s.state = "added";
    s.meltT = MELT_DUR;                 // the seal melts; the upgrade wakes up
    const anim = s.upgradeModel.userData.anim;
    if (anim?.type === "spire") anim.beam.visible = true;
    updateSystems();
    if (allAdded()) {
      // The fifth accept doesn't close the terminal — the finish line is the
      // next command at the prompt you're already at, like the real CLI.
      termMode = "report";
      reviewSite = null;
      explained = false;
      buffer = "";
      termList?.classList.add("hidden");
      flashTerminal("all five systems online", true);
      showTutorial("Every system accounted for — send the day's report: type `entire dispatch`.", 0);
      renderTerminal();
    } else {
      closeTerminal(false);
      showTutorial(`${s.sys.name} online (${addedCount()} / ${lanes.length}).`, 5000);
    }
  }
  // The ADD TO SHIP button (terminal CTA is re-rendered, so delegate the click).
  termCta?.addEventListener("click", (e) => {
    if (!active) return;
    if (e.target?.id === "db-add-btn") addToShip();
  });

  // ---------- the finish line: entire dispatch ----------
  function sendDispatch() {
    reportSent = true;
    timerRunning = false;
    countdownEl?.classList.remove("is-low", "is-critical");
    if (termList) {
      termList.innerHTML =
        `<div class="term-list-row"><span class="tl-key tl-exp-key">DISPATCH</span>` +
        `<span class="tl-title">drone bay — day report</span></div>` +
        lanes.map((l) =>
          `<div class="term-list-row"><span class="tl-key tl-exp-key">·</span>` +
          `<span class="tl-title">${l.sys.name.toLowerCase()} → ${l.sys.became} (${l.sys.ckpt.slice(0, 6)}…)</span></div>`
        ).join("") +
        `<div class="term-list-row"><span class="tl-key tl-exp-key">filed</span>` +
        `<span class="tl-title">from 5 checkpoints · crew: 1 human, 5 subagents</span></div>`;
      termList.classList.remove("hidden");
    }
    flashTerminal("dispatch sent — look how much got done without you", true);
    renderTerminal();
    if (winSub) winSub.textContent = "five jobs in parallel — the report wrote itself";
    winTimer = setTimeout(() => {
      closeTerminal(false);
      tutorialEl?.classList.add("hidden");
      winEl?.classList.remove("hidden");
    }, 4000);
    onComplete?.();               // Level 2 cleared — opens the launch window
  }
  function submitCommand() {
    const n = normalizeCmd(buffer);
    buffer = "";
    if (!n) { renderTerminal(); return; }
    if (/^entire dispatch$/.test(n)) { sendDispatch(); return; }
    if (/^entire (checkpoint|cp) list$/.test(n)) {
      if (termList) {
        termList.innerHTML = lanes.map((l) =>
          `<div class="term-list-row"><span class="tl-id tl-id-short">${l.sys.ckpt}</span>` +
          `<span class="tl-title">subagent fix: ${l.sys.name.toLowerCase()} → ${l.sys.became}</span></div>`
        ).join("");
        termList.classList.remove("hidden");
      }
      flashTerminal("the raw log — now turn it into the day's report:  entire dispatch", true);
      renderTerminal();
      return;
    }
    flashTerminal("command not recognized — try:  entire dispatch", false);
    renderTerminal();
  }

  // ---------- input ----------
  function onCanvasClick(e) {
    if (!active || !started || failed || reportSent) return;
    if (terminalOpen) return;
    const l = laneAtPointer(e);
    if (!l) return;
    if (l.state === "staged") toggleArm(l);
    else if (l.state === "running") boost(l);
    else if (l.state === "sealed") openTerminal("review", l);
  }
  function onCanvasMove(e) {
    if (!active || !started || failed || terminalOpen) { hoverLane = null; return; }
    hoverLane = laneAtPointer(e);
    canvas.style.cursor = (hoverLane && hoverLane.state !== "added") ? "pointer" : "default";
  }
  function onKeyDown(e) {
    if (!active) return;

    // Briefing is up — Enter/Space begins the run, nothing else.
    if (!started) {
      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
      return;
    }

    // The clock ran out — R retries, N returns to the true beginning.
    if (failed) {
      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
      if (e.code === "KeyN") { onNewGame?.(); e.preventDefault(); }
      return;
    }

    // While the terminal is open, all keys feed it.
    if (terminalOpen) {
      if (e.code === "Escape") { closeTerminal(true); e.preventDefault(); return; }
      if (termMode === "review") {
        if (!explained && e.code === "Enter") { runExplain(); e.preventDefault(); return; }
        if (explained && (e.key === "y" || e.key === "Y")) { addToShip(); e.preventDefault(); return; }
        e.preventDefault();
        return;
      }
      // report mode — type the dispatch command (the finish line)
      if (reportSent) { e.preventDefault(); return; }
      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
        buffer += e.key; renderTerminal(); e.preventDefault();
      }
      return;
    }

    // Mission control.
    if (reportSent && e.code === "Enter") { onNext?.(); e.preventDefault(); return; }
    if (e.code === "Space") { greenFlag(); e.preventDefault(); return; }
    if (e.code === "Enter" && allAdded() && !reportSent) {
      reportDismissed = false; openTerminal("report", null); e.preventDefault(); return;
    }
    if (e.code === "KeyB") { onExit?.(); e.preventDefault(); }
  }

  // ---------- HUD per-frame ----------
  function refreshHud() {
    if (!started || terminalOpen) { setPrompt(null); return; }
    if (reportSent) { setPrompt("The day is dispatched — press Enter to board the ship"); return; }
    if (allAdded()) { setPrompt("All systems online — press Enter to send the day's report: `entire dispatch`"); return; }
    if (lanes.some((l) => l.state === "sealed")) {
      setPrompt("Ice-blue means finished work — click that car to review it");
      return;
    }
    if (lanes.some((l) => l.state === "running")) {
      setPrompt(`Cars en route — click one to spend nitro (${nitro} left)`);
      return;
    }
    if (lanes.some((l) => l.state === "staged" && l.armed)) {
      setPrompt("Armed and ready — press SPACE for the green flag");
      return;
    }
    setPrompt("Click a car to arm it");
  }

  // ---------- per-frame ----------
  function update(dt, t) {
    // Level countdown — one clock for the whole run.
    if (active && timerRunning && !failed && !reportSent) {
      timeLeft = Math.max(0, timeLeft - dt);
      updateClock();
      if (timeLeft <= 0) failLevel();
    }
    applyPanicSky();

    // Cars: stage idle, drive their lane, park at the finish.
    for (const l of lanes) {
      const car = l.car;
      if (l.state === "staged") {
        car.position.y = l.start.y + Math.sin((t + l.idx) * 2) * 0.05;
        if (l.armed) {
          const pulse = 0.55 + 0.45 * (0.5 + 0.5 * Math.sin(t * 6));
          car.userData.bodyMat.emissiveIntensity = pulse;
          car.userData.cabin.material.emissiveIntensity = pulse;
        } else {
          car.userData.bodyMat.emissiveIntensity = 0.4;
          car.userData.cabin.material.emissiveIntensity = 0.45;
        }
      } else if (l.state === "running") {
        if (l.boostT > 0) l.boostT = Math.max(0, l.boostT - dt);
        const boosting = l.boostT > 0;
        const speed = BASE_SPEED * (boosting ? BOOST_MULT : 1);
        l.prog = Math.min(1, l.prog + speed * dt);
        const k = l.prog;
        const x = l.start.x + (l.finish.x - l.start.x) * k;
        const z = l.start.z + (l.finish.z - l.start.z) * k;
        car.position.set(x, terrain.heightAt(x, z) + 0.6, z);
        const spin = (boosting ? 18 : 7) * dt;
        for (const w of car.userData.wheels) w.rotation.x += spin;
        car.userData.glow.material.opacity = boosting ? 0.55 + 0.25 * Math.sin(t * 30) : 0;
        car.userData.bodyMat.emissiveIntensity = boosting ? 1.4 : 0.7;
        if (boosting && Math.random() < dt * 12) {
          spawnSpark(car.position.clone().setY(car.position.y + 0.4), 0xffb86b, 4);
        }
        if (l.prog >= 1) sealSite(l);
      }

      // hover lift on interactable cars
      const interactable = l.state === "staged" || l.state === "running" || l.state === "sealed";
      if (hoverLane === l && interactable) {
        car.userData.cabin.material.emissiveIntensity = 1.1;
      }
    }

    // Systems: status beams, warning blinks, seals, and live upgrades.
    for (const l of lanes) {
      if (l.state === "staged") {
        l.beam.material.color.setHex(0xff8a5c);
        l.beam.material.opacity = 0.24 + Math.sin(t * 1.6 + l.idx) * 0.08;
        l.beam.visible = true;
        const warn = l.brokenModel.userData.warn;
        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + l.idx) > 0 ? 1.8 : 0.2;
      } else if (l.state === "running") {
        l.beam.material.color.setHex(0x6fe3ff);
        l.beam.material.opacity = 0.4 + Math.sin(t * 6) * 0.18;
        l.beam.visible = true;
        const warn = l.brokenModel.userData.warn;
        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + l.idx) > 0 ? 1.8 : 0.2;
      } else if (l.state === "sealed") {
        l.beam.material.color.setHex(0x8fe3ff);
        l.beam.material.opacity = 0.42;
        l.beam.visible = true;
      } else {
        l.beam.visible = false;       // added — the upgrade itself is the landmark
        if (l.meltT > 0) {
          l.meltT = Math.max(0, l.meltT - dt);
          l.ice.material.opacity = 0.62 * (l.meltT / MELT_DUR);
          if (l.meltT <= 0) l.ice.visible = false;
        }
        const anim = l.upgradeModel.userData.anim;
        if (anim?.type === "ring") {
          anim.ring.rotation.y += dt * 0.8;
          anim.ring.position.y = 3.4 + Math.sin(t * 1.6) * 0.2;
        } else if (anim?.type === "dome") {
          anim.field.rotation.y += dt * 0.25;
          anim.orbit.rotation.z += dt * 0.6;
        } else if (anim?.type === "skid") {
          anim.pad.position.y = 1.6 + Math.sin(t * 1.8) * 0.25;
        }
      }
    }

    // Spark bursts.
    for (let i = sparks.length - 1; i >= 0; i--) {
      const s = sparks[i];
      s.life += dt;
      const pos = s.geo.attributes.position.array;
      for (let j = 0; j < s.vel.length; j++) {
        s.vel[j].y -= 14 * dt;
        pos[j * 3] += s.vel[j].x * dt;
        pos[j * 3 + 1] += s.vel[j].y * dt;
        pos[j * 3 + 2] += s.vel[j].z * dt;
      }
      s.geo.attributes.position.needsUpdate = true;
      s.mat.opacity = Math.max(0, 1 - s.life / s.ttl);
      if (s.life >= s.ttl) {
        scene.remove(s.pts);
        s.geo.dispose(); s.mat.dispose();
        sparks.splice(i, 1);
      }
    }

    consoleGlow.intensity = allAdded() && !reportSent ? 8 + Math.sin(t * 4) * 3 : 5;

    // The report terminal opens itself once every system is online.
    if (active && started && !failed) {
      if (!terminalOpen && allAdded() && !reportSent && !reportDismissed) {
        openTerminal("report", null);
      }
    }

    if (active) refreshHud();
  }

  // ---------- lifecycle ----------
  function enter() {
    active = true;
    camera.position.set(0, 32, 104);
    camera.lookAt(0, 2, 4);
    canvas.addEventListener("click", onCanvasClick);
    canvas.addEventListener("mousemove", onCanvasMove);
    window.addEventListener("keydown", onKeyDown);
    dbHud?.classList.remove("hidden");
    fpShared?.classList.remove("hidden");
    crosshair?.classList.add("hidden");
    setControls();
    updateSystems();
    if (!started) {
      showBriefing();
    } else if (reportSent) {
      winEl?.classList.remove("hidden");
    } else if (failed) {
      resetLevel();
    } else {
      timerRunning = true;
      showTutorial("The cars kept rolling while you were in orbit.", 5000);
    }
    updateClock();
    applyPanicSky();
  }
  function exit() {
    active = false;
    timerRunning = false;
    closeTerminal(false);
    clearTimeout(winTimer);
    canvas.removeEventListener("click", onCanvasClick);
    canvas.removeEventListener("mousemove", onCanvasMove);
    window.removeEventListener("keydown", onKeyDown);
    canvas.style.cursor = "default";
    setPrompt(null);
    hideControls();
    tutorialEl?.classList.add("hidden");
    termEl?.classList.add("hidden");
    failEl?.classList.add("hidden");
    winEl?.classList.add("hidden");
    briefingEl?.classList.add("hidden");
    dbHud?.classList.add("hidden");
    fpShared?.classList.add("hidden");
    crosshair?.classList.add("hidden");
  }
  function resize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
  }

  return {
    scene,
    get camera() { return camera; },
    update, enter, exit, resize,
  };
}

