1	import * as THREE from "three";
2	import { createTerrain } from "./terrain.js";
3	import { makeBeamTexture, makeIceBlock, makeIdSprite } from "./memoryProps.js";
4	
5	// LEVEL 2 ("The Drone Bay") — mission control, not a foot race.
6	//
7	// The day-to-day agentic loop, played as a starting grid. Five ship systems
8	// are dark out across the island; five cars (subagents) wait at the bay. You
9	// don't run — you ORCHESTRATE:
10	//
11	//   click a car            → it arms (engine lit)
12	//   press SPACE            → every armed car launches at once (the green flag)
13	//   click a car mid-run    → spend a nitro charge, it surges (catch-up tool)
14	//   a car reaches its system → its work seals under a checkpoint (ice beam)
15	//   click the parked car   → `entire checkpoint explain <id>` is PRE-FILLED
16	//   read what it did       → ADD TO SHIP (Y) → system online
17	//   all five online        → type `entire dispatch` — the day writes itself
18	//
19	// Arm one and green-flag at a time = sequential. Arm all five, one green flag
20	// = parallel — the fast clear. Nothing forces parallel; the clock just rewards
21	// it. Cars IMPROVISE (a bent dish comes back as a signal spire); the transform
22	// is what makes you NEED the explanation.
23	
24	const TOTAL_TIME = 150;      // seconds for the whole run (tunable)
25	const BASE_SPEED = 1 / 14;   // lane progress per second (un-boosted ≈ 14s)
26	const BOOST_MULT = 2.6;      // nitro speed multiplier
27	const BOOST_DUR  = 2.2;      // seconds a nitro surge lasts
28	const NITRO_MAX  = 3;        // charges per run
29	const LOW_TIME = 45;         // clock turns urgent under this
30	const CRIT_TIME = 15;        // clock goes CRITICAL under this
31	const PANIC_TIME = 45;       // the SKY starts shifting toward panic-red
32	const MELT_DUR = 1.2;        // seconds the ice takes to melt on ADD TO SHIP
33	
34	// Starting grid — five parallel lanes fanning slightly out to the systems.
35	const START_Z = 64;
36	const FINISH_Z = -34;
37	const LANE = (i) => ({ startX: (i - 2) * 14, finishX: (i - 2) * 24 });
38	
39	// Sky panic palette — same dread as Level 1's clock.
40	const SKY_CALM  = new THREE.Color(0x2a2350);
41	const SKY_PANIC = new THREE.Color(0x6e0f16);
42	const FOG_PANIC = new THREE.Color(0x4a0a0e);
43	const DOME_CALM = new THREE.Color(0x3a3168);
44	const DOME_PANIC = new THREE.Color(0x7a141c);
45	const SUN_CALM  = new THREE.Color(0xfff1dc);
46	const SUN_PANIC = new THREE.Color(0xff5a3c);
47	
48	// The five dark systems, what the cars improvise them into, and the story each
49	// checkpoint carries. Ids are fixed so the fiction is stable across runs.
50	// Exported: Level 3 quizzes the player on this exact record (and uses sys.pos
51	// on its own island — left untouched here; this level lays out its own grid).
