308	// ---------- the little worker car ----------
309	function buildCar() {
310	  const g = new THREE.Group();
311	  const bodyMat = new THREE.MeshStandardMaterial({
312	    color: 0x2c3140, metalness: 0.6, roughness: 0.35, emissive: 0x2a8aa6, emissiveIntensity: 0.55,
313	  });
314	  const body = new THREE.Mesh(new THREE.BoxGeometry(2.1, 0.7, 3.4), bodyMat);
315	  body.position.y = 1.0;
316	  const nose = new THREE.Mesh(new THREE.BoxGeometry(1.6, 0.5, 0.9), bodyMat);
317	  nose.position.set(0, 0.95, -2.0);
318	  const cabin = new THREE.Mesh(
319	    new THREE.BoxGeometry(1.4, 0.7, 1.5),
320	    new THREE.MeshStandardMaterial({ color: 0x0c2030, emissive: 0x6fe3ff, emissiveIntensity: 0.55, metalness: 0.4, roughness: 0.3 })
321	  );
322	  cabin.position.set(0, 1.55, 0.1);
323	  const wheelGeo = new THREE.CylinderGeometry(0.5, 0.5, 0.4, 12);
324	  const wheelMat = new THREE.MeshStandardMaterial({ color: 0x10141c, roughness: 0.8, metalness: 0.2 });
325	  const wheels = [];
326	  for (const dx of [-1.05, 1.05]) {
327	    for (const dz of [-1.15, 1.15]) {
328	      const w = new THREE.Mesh(wheelGeo, wheelMat);
329	      w.rotation.z = Math.PI / 2;
330	      w.position.set(dx, 0.5, dz);
331	      wheels.push(w);
332	      g.add(w);
333	    }
334	  }
335	  // Nitro flare — a glow under the car, lit only while boosting.
336	  const glow = new THREE.Mesh(
337	    new THREE.PlaneGeometry(2.8, 4.2),
338	    new THREE.MeshBasicMaterial({
339	      color: 0xffb86b, transparent: true, opacity: 0, blending: THREE.AdditiveBlending, depthWrite: false,
340	    })
341	  );
342	  glow.rotation.x = -Math.PI / 2;
343	  glow.position.y = 0.12;
344	  g.add(body, nose, cabin, glow);
345	  g.userData = { bodyMat, cabin, glow, wheels };
346	  return g;
347	}
