369	export function createDroneBayView(renderer, { onExit, onComplete, onNext, onNewGame } = {}) {
370	  const canvas = renderer.domElement;
371	
372	  // ---------- scene & sky ----------
373	  const scene = new THREE.Scene();
374	  scene.background = SKY_CALM.clone();
375	  scene.fog = new THREE.Fog(SKY_CALM.clone(), 120, 360);
376	
377	  const camera = new THREE.PerspectiveCamera(
378	    60, window.innerWidth / window.innerHeight, 0.1, 2000
379	  );
380	  // Fixed mission-control vantage: behind the grid, looking out at the systems.
381	  camera.position.set(0, 32, 104);
382	  camera.lookAt(0, 2, 4);
383	
384	  // ---------- lighting ----------
385	  scene.add(new THREE.HemisphereLight(0xcdbcff, 0x3a2f5e, 0.7));
386	  const sun = new THREE.DirectionalLight(SUN_CALM, 1.5);
387	  sun.position.set(60, 90, 40);
388	  scene.add(sun);
