470	  function railGeo(a, b, offX, terr) {
471	    const N = 24;
472	    const pts = [];
473	    for (let i = 0; i <= N; i++) {
474	      const k = i / N;
475	      const x = a.x + (b.x - a.x) * k + offX;
476	      const z = a.z + (b.z - a.z) * k;
477	      pts.push(new THREE.Vector3(x, terr.heightAt(x, z) + 0.25, z));
478	    }
479	    return new THREE.BufferGeometry().setFromPoints(pts);
480	  }
