897	    if (winSub) winSub.textContent = "five jobs in parallel — the report wrote itself";
898	    winTimer = setTimeout(() => {
899	      closeTerminal(false);
900	      tutorialEl?.classList.add("hidden");
901	      winEl?.classList.remove("hidden");
902	    }, 4000);
903	    onComplete?.();               // Level 2 cleared — opens the launch window
904	  }
905	  function submitCommand() {
906	    const n = normalizeCmd(buffer);
907	    buffer = "";
908	    if (!n) { renderTerminal(); return; }
909	    if (/^entire dispatch$/.test(n)) { sendDispatch(); return; }
910	    if (/^entire (checkpoint|cp) list$/.test(n)) {
911	      if (termList) {
912	        termList.innerHTML = lanes.map((l) =>
913	          `<div class="term-list-row"><span class="tl-id tl-id-short">${l.sys.ckpt}</span>` +
914	          `<span class="tl-title">subagent fix: ${l.sys.name.toLowerCase()} → ${l.sys.became}</span></div>`
915	        ).join("");
916	        termList.classList.remove("hidden");
917	      }
918	      flashTerminal("the raw log — now turn it into the day's report:  entire dispatch", true);
919	      renderTerminal();
920	      return;
921	    }
922	    flashTerminal("command not recognized — try:  entire dispatch", false);
923	    renderTerminal();
924	  }
