926	  // ---------- input ----------
927	  function onCanvasClick(e) {
928	    if (!active || !started || failed || reportSent) return;
929	    if (terminalOpen) return;
930	    const l = laneAtPointer(e);
931	    if (!l) return;
932	    if (l.state === "staged") toggleArm(l);
933	    else if (l.state === "running") boost(l);
934	    else if (l.state === "sealed") openTerminal("review", l);
935	  }
936	  function onCanvasMove(e) {
937	    if (!active || !started || failed || terminalOpen) { hoverLane = null; return; }
938	    hoverLane = laneAtPointer(e);
939	    canvas.style.cursor = (hoverLane && hoverLane.state !== "added") ? "pointer" : "default";
940	  }
941	  function onKeyDown(e) {
942	    if (!active) return;
943	
944	    // Briefing is up — Enter/Space begins the run, nothing else.
945	    if (!started) {
946	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
947	      return;
948	    }
949	
950	    // The clock ran out — R retries, N returns to the true beginning.
951	    if (failed) {
952	      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
953	      if (e.code === "KeyN") { onNewGame?.(); e.preventDefault(); }
954	      return;
955	    }
956	
957	    // While the terminal is open, all keys feed it.
958	    if (terminalOpen) {
959	      if (e.code === "Escape") { closeTerminal(true); e.preventDefault(); return; }
960	      if (termMode === "review") {
961	        if (!explained && e.code === "Enter") { runExplain(); e.preventDefault(); return; }
962	        if (explained && (e.key === "y" || e.key === "Y")) { addToShip(); e.preventDefault(); return; }
963	        e.preventDefault();
964	        return;
965	      }
966	      // report mode — type the dispatch command (the finish line)
967	      if (reportSent) { e.preventDefault(); return; }
968	      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
969	      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
970	      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
971	        buffer += e.key; renderTerminal(); e.preventDefault();
972	      }
973	      return;
974	    }
975	
976	    // Mission control.
977	    if (reportSent && e.code === "Enter") { onNext?.(); e.preventDefault(); return; }
978	    if (e.code === "Space") { greenFlag(); e.preventDefault(); return; }
979	    if (e.code === "Enter" && allAdded() && !reportSent) {
980	      reportDismissed = false; openTerminal("report", null); e.preventDefault(); return;
981	    }
982	    if (e.code === "KeyB") { onExit?.(); e.preventDefault(); }
983	  }
