987	    if (!started || terminalOpen) { setPrompt(null); return; }
988	    if (reportSent) { setPrompt("The day is dispatched — press Enter to board the ship"); return; }
989	    if (allAdded()) { setPrompt("All systems online — press Enter to send the day's report: `entire dispatch`"); return; }
990	    if (lanes.some((l) => l.state === "sealed")) {
991	      setPrompt("Ice-blue means finished work — click that car to review it");
992	      return;
993	    }
994	    if (lanes.some((l) => l.state === "running")) {
995	      setPrompt(`Cars en route — click one to spend nitro (${nitro} left)`);
996	      return;
997	    }
998	    if (lanes.some((l) => l.state === "staged" && l.armed)) {
