1005	  // ---------- per-frame ----------
1006	  function update(dt, t) {
1007	    // Level countdown — one clock for the whole run.
1008	    if (active && timerRunning && !failed && !reportSent) {
1009	      timeLeft = Math.max(0, timeLeft - dt);
1010	      updateClock();
1011	      if (timeLeft <= 0) failLevel();
1012	    }
1013	    applyPanicSky();
1014	
1015	    // Cars: stage idle, drive their lane, park at the finish.
1016	    for (const l of lanes) {
1017	      const car = l.car;
1018	      if (l.state === "staged") {
1019	        car.position.y = l.start.y + Math.sin((t + l.idx) * 2) * 0.05;
1020	        if (l.armed) {
1021	          const pulse = 0.55 + 0.45 * (0.5 + 0.5 * Math.sin(t * 6));
1022	          car.userData.bodyMat.emissiveIntensity = pulse;
1023	          car.userData.cabin.material.emissiveIntensity = pulse;
1024	        } else {
1025	          car.userData.bodyMat.emissiveIntensity = 0.4;
1026	          car.userData.cabin.material.emissiveIntensity = 0.45;
1027	        }
1028	      } else if (l.state === "running") {
1029	        if (l.boostT > 0) l.boostT = Math.max(0, l.boostT - dt);
1030	        const boosting = l.boostT > 0;
1031	        const speed = BASE_SPEED * (boosting ? BOOST_MULT : 1);
1032	        l.prog = Math.min(1, l.prog + speed * dt);
1033	        const k = l.prog;
1034	        const x = l.start.x + (l.finish.x - l.start.x) * k;
1035	        const z = l.start.z + (l.finish.z - l.start.z) * k;
1036	        car.position.set(x, terrain.heightAt(x, z) + 0.6, z);
1037	        const spin = (boosting ? 18 : 7) * dt;
1038	        for (const w of car.userData.wheels) w.rotation.x += spin;
1039	        car.userData.glow.material.opacity = boosting ? 0.55 + 0.25 * Math.sin(t * 30) : 0;
1040	        car.userData.bodyMat.emissiveIntensity = boosting ? 1.4 : 0.7;
1041	        if (boosting && Math.random() < dt * 12) {
1042	          spawnSpark(car.position.clone().setY(car.position.y + 0.4), 0xffb86b, 4);
1043	        }
1044	        if (l.prog >= 1) sealSite(l);
1045	      }
1046	
1047	      // hover lift on interactable cars
1048	      const interactable = l.state === "staged" || l.state === "running" || l.state === "sealed";
1049	      if (hoverLane === l && interactable) {
1050	        car.userData.cabin.material.emissiveIntensity = 1.1;
1051	      }
1052	    }
1053	
1054	    // Systems: status beams, warning blinks, seals, and live upgrades.
1055	    for (const l of lanes) {
1056	      if (l.state === "staged") {
1057	        l.beam.material.color.setHex(0xff8a5c);
1058	        l.beam.material.opacity = 0.24 + Math.sin(t * 1.6 + l.idx) * 0.08;
1059	        l.beam.visible = true;
1060	        const warn = l.brokenModel.userData.warn;
1061	        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + l.idx) > 0 ? 1.8 : 0.2;
1062	      } else if (l.state === "running") {
1063	        l.beam.material.color.setHex(0x6fe3ff);
1064	        l.beam.material.opacity = 0.4 + Math.sin(t * 6) * 0.18;
1065	        l.beam.visible = true;
1066	        const warn = l.brokenModel.userData.warn;
1067	        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + l.idx) > 0 ? 1.8 : 0.2;
1068	      } else if (l.state === "sealed") {
1069	        l.beam.material.color.setHex(0x8fe3ff);
1070	        l.beam.material.opacity = 0.42;
1071	        l.beam.visible = true;
1072	      } else {
1073	        l.beam.visible = false;       // added — the upgrade itself is the landmark
1074	        if (l.meltT > 0) {
1075	          l.meltT = Math.max(0, l.meltT - dt);
1076	          l.ice.material.opacity = 0.62 * (l.meltT / MELT_DUR);
1077	          if (l.meltT <= 0) l.ice.visible = false;
1078	        }
1079	        const anim = l.upgradeModel.userData.anim;
1080	        if (anim?.type === "ring") {
1081	          anim.ring.rotation.y += dt * 0.8;
1082	          anim.ring.position.y = 3.4 + Math.sin(t * 1.6) * 0.2;
1083	        } else if (anim?.type === "dome") {
1084	          anim.field.rotation.y += dt * 0.25;
1085	          anim.orbit.rotation.z += dt * 0.6;
1086	        } else if (anim?.type === "skid") {
1087	          anim.pad.position.y = 1.6 + Math.sin(t * 1.8) * 0.25;
1088	        }
1089	      }
1090	    }
1091	
1092	    // Spark bursts.
1093	    for (let i = sparks.length - 1; i >= 0; i--) {
1094	      const s = sparks[i];
1095	      s.life += dt;
1096	      const pos = s.geo.attributes.position.array;
1097	      for (let j = 0; j < s.vel.length; j++) {
1098	        s.vel[j].y -= 14 * dt;
1099	        pos[j * 3] += s.vel[j].x * dt;
1100	        pos[j * 3 + 1] += s.vel[j].y * dt;
1101	        pos[j * 3 + 2] += s.vel[j].z * dt;
1102	      }
1103	      s.geo.attributes.position.needsUpdate = true;
1104	      s.mat.opacity = Math.max(0, 1 - s.life / s.ttl);
1105	      if (s.life >= s.ttl) {
1106	        scene.remove(s.pts);
1107	        s.geo.dispose(); s.mat.dispose();
1108	        sparks.splice(i, 1);
1109	      }
1110	    }
1111	
1112	    consoleGlow.intensity = allAdded() && !reportSent ? 8 + Math.sin(t * 4) * 3 : 5;
1113	
1114	    // The report terminal opens itself once every system is online.
1115	    if (active && started && !failed) {
1116	      if (!terminalOpen && allAdded() && !reportSent && !reportDismissed) {
1117	        openTerminal("report", null);
1118	      }
1119	    }
1120	
1121	    if (active) refreshHud();
1122	  }
1123	
1124	  // ---------- lifecycle ----------
