  font-size: 10px;
  letter-spacing: 0.2em;
  font-weight: 700;
  color: #ffb86b;
}
.db-nitro-dots { display: flex; gap: 6px; }
.db-nitro-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: #ffb86b;
