  { at: 0.34, len: 0.18, severe: true  },  // ignition coils
  { at: 0.50, len: 0.10, severe: false },  // nav core
  { at: 0.40, len: 0.18, severe: true  },  // antenna
  { at: 0.58, len: 0.10, severe: false },  // life support
  { at: 0.46, len: 0.12, severe: false },  // struts
];

