// Per-lane corruption patch. Every third lane is severe (must be boosted);
// the rest just slow you. Staggered along the track so they don't all hit at once.
const HAZARDS = JOBS.map((_, i) => {
  const severe = i % 3 === 0;
  return { at: 0.30 + (i % 4) * 0.06, len: severe ? 0.18 : 0.10, severe };
});

function normalizeCmd(s) {
  return s.trim().toLowerCase().replace(/\s+/g, " ");
}

