// ---------- the little worker car ----------
function buildCar() {
  const g = new THREE.Group();
  const bodyMat = new THREE.MeshStandardMaterial({
    color: 0x2c3140, metalness: 0.6, roughness: 0.35, emissive: 0x2a8aa6, emissiveIntensity: 0.55,
  });
  const body = new THREE.Mesh(new THREE.BoxGeometry(2.1, 0.7, 3.4), bodyMat);
  body.position.y = 1.0;
  const nose = new THREE.Mesh(new THREE.BoxGeometry(1.6, 0.5, 0.9), bodyMat);
  nose.position.set(0, 0.95, -2.0);
  const cabin = new THREE.Mesh(
    new THREE.BoxGeometry(1.4, 0.7, 1.5),
    new THREE.MeshStandardMaterial({ color: 0x0c2030, emissive: 0x6fe3ff, emissiveIntensity: 0.55, metalness: 0.4, roughness: 0.3 })
  );
  cabin.position.set(0, 1.55, 0.1);
  const wheelGeo = new THREE.CylinderGeometry(0.5, 0.5, 0.4, 12);
  const wheelMat = new THREE.MeshStandardMaterial({ color: 0x10141c, roughness: 0.8, metalness: 0.2 });
  const wheels = [];
  for (const dx of [-1.05, 1.05]) {
    for (const dz of [-1.15, 1.15]) {
      const w = new THREE.Mesh(wheelGeo, wheelMat);
      w.rotation.z = Math.PI / 2;
      w.position.set(dx, 0.5, dz);
      wheels.push(w);
      g.add(w);
    }
  }
  const glow = new THREE.Mesh(
    new THREE.PlaneGeometry(2.8, 4.2),
    new THREE.MeshBasicMaterial({
      color: 0xffb86b, transparent: true, opacity: 0, blending: THREE.AdditiveBlending, depthWrite: false,
    })
  );
  glow.rotation.x = -Math.PI / 2;
  glow.position.y = 0.12;
  g.add(body, nose, cabin, glow);
  g.userData = { bodyMat, cabin, glow, wheels };
  return g;
}

// ---------- a volumetric corruption patch (reads at a low camera angle) ----------
function buildHazard(severe) {
  const g = new THREE.Group();
  const r = severe ? 3.4 : 2.2;
  const shardMat = new THREE.MeshStandardMaterial({
    color: 0x3a0a0a, emissive: 0xff3320, emissiveIntensity: 1.4, roughness: 0.5, metalness: 0.2,
  });
  const n = severe ? 7 : 5;
  for (let i = 0; i < n; i++) {
    const h = (severe ? 2.6 : 1.6) * (0.6 + Math.random() * 0.7);
    const shard = new THREE.Mesh(new THREE.ConeGeometry(0.5 + Math.random() * 0.4, h, 5), shardMat);
    const a = (i / n) * Math.PI * 2 + Math.random() * 0.4;
    const rad = Math.random() * r * 0.7;
    shard.position.set(Math.cos(a) * rad, h * 0.5, Math.sin(a) * rad);
    shard.rotation.set((Math.random() - 0.5) * 0.5, Math.random() * Math.PI, (Math.random() - 0.5) * 0.5);
    g.add(shard);
  }
  const domeMat = new THREE.MeshBasicMaterial({
    color: 0xff5530, transparent: true, opacity: 0.18, side: THREE.DoubleSide,
    depthWrite: false, blending: THREE.AdditiveBlending,
  });
  const dome = new THREE.Mesh(new THREE.SphereGeometry(r, 16, 10, 0, Math.PI * 2, 0, Math.PI / 2), domeMat);
  g.add(dome);
  const ringMat = new THREE.MeshBasicMaterial({ color: 0xffae66, transparent: true, opacity: 0.7 });
  const ring = new THREE.Mesh(new THREE.TorusGeometry(r, 0.12, 8, 32), ringMat);
  ring.rotation.x = -Math.PI / 2;
  ring.position.y = 0.15;
  g.add(ring);
  g.userData = { shardMat, domeMat, ringMat, severe, r };
  return g;
}

// The ship console behind the bay (decoration / where the report fires).
function makeConsole() {
