}

export function createDroneBayView(renderer, { onExit, onComplete, onNext, onNewGame } = {}) {
  const canvas = renderer.domElement;

  // ---------- scene & sky ----------
  const scene = new THREE.Scene();
  scene.background = SKY_CALM.clone();
  scene.fog = new THREE.Fog(SKY_CALM.clone(), 140, 420);

  const camera = new THREE.PerspectiveCamera(
    60, window.innerWidth / window.innerHeight, 0.1, 2000
  );

  // ---------- mission-control camera (orbit + zoom around a target) ----------
  const camTarget = new THREE.Vector3(0, 0, 14);
  let camRadius = 124, camTheta = 0, camPhi = 1.2;
  function updateCamera() {
    const sinPhi = Math.sin(camPhi);
    camera.position.set(
      camTarget.x + camRadius * sinPhi * Math.sin(camTheta),
      camTarget.y + camRadius * Math.cos(camPhi),
      camTarget.z + camRadius * sinPhi * Math.cos(camTheta)
    );
    camera.lookAt(camTarget);
  }
  updateCamera();

  // ---------- lighting ----------
  scene.add(new THREE.HemisphereLight(0xcdbcff, 0x3a2f5e, 0.7));
  const sun = new THREE.DirectionalLight(SUN_CALM, 1.5);
  sun.position.set(60, 90, 40);
  scene.add(sun);
  scene.add(new THREE.AmbientLight(0x6a5a92, 0.3));

  const dome = new THREE.Mesh(
    new THREE.SphereGeometry(900, 32, 16),
    new THREE.MeshBasicMaterial({ color: DOME_CALM.clone(), side: THREE.BackSide, fog: false })
  );
  scene.add(dome);

  // ---------- terrain (the same island) ----------
  const terrain = createTerrain({ size: 200, segments: 220, maxHeight: 26, seed: 1337 });
  scene.add(terrain.mesh, terrain.water);

  const beamTex = makeBeamTexture();

  const BUILD = {
    buildBrokenCoils, buildBrokenNav, buildBrokenDish, buildBrokenVent, buildBrokenStrut,
    buildPlasmaRing, buildStarDome, buildGardenPod, buildGravSkid,
    buildSignalSpire: () => buildSignalSpire(beamTex),
  };

  function railGeo(a, b, offX, terr) {
    const NP = 24;
    const pts = [];
    for (let i = 0; i <= NP; i++) {
      const k = i / NP;
      const x = a.x + (b.x - a.x) * k + offX;
      const z = a.z + (b.z - a.z) * k;
      pts.push(new THREE.Vector3(x, terr.heightAt(x, z) + 0.25, z));
    }
    return new THREE.BufferGeometry().setFromPoints(pts);
  }

  // ---------- the twelve lanes ----------
  const N = JOBS.length;
  const lanes = JOBS.map((data, idx) => {
    const { startX, finishX } = LANE(idx, N);
    const start = new THREE.Vector3(startX, terrain.heightAt(startX, START_Z) + 0.6, START_Z);
    const finish = new THREE.Vector3(finishX, terrain.heightAt(finishX, FINISH_Z), FINISH_Z);
    const hazard = HAZARDS[idx];

    const anchor = new THREE.Group();
    anchor.position.copy(finish);
    const brokenModel = BUILD[data.broken]();
    const upgradeModel = BUILD[data.upgrade]();
    upgradeModel.visible = false;
    anchor.add(brokenModel, upgradeModel);

    // Status beam — taller and brighter so it reads from across the yard.
    const beam = new THREE.Mesh(
      new THREE.CylinderGeometry(1.0, 1.0, 80, 12, 1, true),
      new THREE.MeshBasicMaterial({
        map: beamTex, color: 0xff8a5c, transparent: true, opacity: 0.34,
        blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide, fog: false,
      })
    );
    beam.position.y = 46;
    anchor.add(beam);

    const ice = makeIceBlock();
    ice.scale.setScalar(1.25);
    ice.position.y = 2.6;
    ice.visible = false;
    anchor.add(ice);
    const sprite = makeIdSprite(data.ckpt);
    sprite.position.y = 8.4;
    sprite.visible = false;
    anchor.add(sprite);

    // Invisible click target for reviewing a sealed job (the car drives off).
    const reviewHit = new THREE.Mesh(
      new THREE.BoxGeometry(7, 9, 7),
      new THREE.MeshBasicMaterial({ transparent: true, opacity: 0, depthWrite: false })
    );
    reviewHit.position.y = 3.5;
    reviewHit.userData.reviewLaneIdx = idx;
    anchor.add(reviewHit);
    scene.add(anchor);

    const railMat = new THREE.LineBasicMaterial({ color: 0x35506a, transparent: true, opacity: 0.6 });
    const railL = new THREE.Line(railGeo(start, finish, -1.2, terrain), railMat);
    const railR = new THREE.Line(railGeo(start, finish, 1.2, terrain), railMat);
    scene.add(railL, railR);

    const hzFrac = hazard.at + hazard.len / 2;
    const hx = start.x + (finish.x - start.x) * hzFrac;
    const hzz = start.z + (finish.z - start.z) * hzFrac;
    const hzMesh = buildHazard(hazard.severe);
    hzMesh.position.set(hx, terrain.heightAt(hx, hzz) + 0.3, hzz);
    scene.add(hzMesh);

    return {
      data, idx, start, finish, hazard, anchor, brokenModel, upgradeModel, beam, ice, sprite,
      reviewHit, railL, railR, railMat, hzMesh,
      carObj: null,
      state: "empty",          // empty → loaded → running → sealed → added
      prog: 0, boostT: 0, corrupt: 0, meltT: 0,
      stalled: false, hazardCleared: false,
    };
  });

  // ---------- the car pool ----------
  const cars = Array.from({ length: N_CARS }, (_, i) => {
    const mesh = buildCar();
    const x = baySlotX(i, N_CARS);
    const home = new THREE.Vector3(x, terrain.heightAt(x, BAY_Z) + 0.6, BAY_Z);
    mesh.position.copy(home);
    mesh.userData.carIdx = i;
    scene.add(mesh);
    return {
      mesh, home, idx: i, state: "bay", lane: null,    // bay → loaded → running → returning → bay
      retProg: 0, retFrom: null, retTo: null,
    };
  });

  // ---------- the ship console (behind the bay) ----------
  const consoleAnchor = new THREE.Group();
  const cz = BAY_Z + 12;
  consoleAnchor.position.set(0, terrain.heightAt(0, cz), cz);
  consoleAnchor.add(makeConsole());
  const consoleGlow = new THREE.PointLight(0xffd27a, 5, 28, 2);
  consoleGlow.position.y = 5;
  consoleAnchor.add(consoleGlow);
  scene.add(consoleAnchor);

  // ---------- spark bursts ----------
  const sparks = [];
  function spawnSpark(pos, color = 0x9af0ff, n = 14) {
    const arr = new Float32Array(n * 3);
    const vel = [];
    for (let i = 0; i < n; i++) {
      arr[i * 3] = pos.x; arr[i * 3 + 1] = pos.y; arr[i * 3 + 2] = pos.z;
      vel.push(new THREE.Vector3((Math.random() - 0.5) * 9, Math.random() * 7, (Math.random() - 0.5) * 9));
    }
    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(arr, 3));
    const mat = new THREE.PointsMaterial({
      color, size: 0.45, transparent: true, opacity: 1,
      blending: THREE.AdditiveBlending, depthWrite: false,
    });
    const pts = new THREE.Points(geo, mat);
    scene.add(pts);
    sparks.push({ pts, geo, mat, vel, life: 0, ttl: 0.7 });
  }

  // ---------- HUD elements ----------
  const promptEl = document.getElementById("fp-prompt");
  const controlsEl = document.getElementById("fp-controls");
  const crosshair = document.getElementById("crosshair");
  const tutorialEl = document.getElementById("tutorial");
  const fpShared = document.getElementById("fp-shared");
  const termEl = document.getElementById("terminal");
  const termHint = document.getElementById("term-hint");
  const termInput = document.getElementById("term-input");
  const termList = document.getElementById("term-list");
  const termMsg = document.getElementById("term-msg");
  const termCta = document.getElementById("term-cta");
  const dbHud = document.getElementById("db-hud");
  const briefingEl = document.getElementById("db-briefing");
  const briefingTextEl = document.getElementById("db-briefing-text");
  const briefingNextEl = document.getElementById("db-briefing-next");
  const countdownEl = document.getElementById("db-countdown");
  const countdownTime = document.getElementById("db-countdown-time");
  const systemsEl = document.getElementById("db-systems-rows");
  const winEl = document.getElementById("db-win");
  const winSub = document.getElementById("db-win-sub");
  const failEl = document.getElementById("db-fail");

  let active = false;
  let started = false;
  let failed = false;
  let reportSent = false;
  let promptText = null;
  const taught = new Set();
  let tutorialTimer = null;
  let msgTimer = null;
  let winTimer = null;
  let nitro = NITRO_MAX;
  let briefingIndex = 0;

  let timeLeft = TOTAL_TIME;
  let timerRunning = false;
  let clockStarted = false;

  let terminalOpen = false;
  let termMode = null;
  let reviewSite = null;
  let explained = false;
  let buffer = "";
  let reportDismissed = false;

  const addedCount = () => lanes.filter((l) => l.state === "added").length;
  const allAdded = () => addedCount() >= lanes.length;
  const loadedCount = () => lanes.filter((l) => l.state === "loaded").length;
  const anyRunning = () => lanes.some((l) => l.state === "running");
  const anySealed = () => lanes.some((l) => l.state === "sealed");
  const openTracks = () => lanes.some((l) => l.state === "empty");
  const carsFree = () => cars.some((c) => c.state === "bay");
  const allHome = () => lanes.every((l) => l.state === "sealed" || l.state === "added");

  // ---------- raycasting / pointer ----------
  const raycaster = new THREE.Raycaster();
  const ndc = new THREE.Vector2();
  const groundPlane = new THREE.Plane(new THREE.Vector3(0, 1, 0), 0);
  let hoverCar = null;
  let pointerDown = false;
  let picked = null;            // car under the cursor at mousedown
  let pickedJob = null;         // sealed job under the cursor at mousedown
  let pickedKind = null;        // "car" | "job" | "camera"
  let pickedDraggable = false;
  let dragging = false;
  let downX = 0, downY = 0, lastX = 0, lastY = 0;
  let dropTarget = null;

  function setNdc(e) {
    const rect = canvas.getBoundingClientRect();
    ndc.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
    ndc.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
  }
  function carAtPointer(e) {
    setNdc(e);
    raycaster.setFromCamera(ndc, camera);
    const hits = raycaster.intersectObjects(cars.map((c) => c.mesh), true);
    if (!hits.length) return null;
    let o = hits[0].object;
    while (o && o.userData.carIdx === undefined) o = o.parent;
    return o ? cars[o.userData.carIdx] : null;
  }
  function jobAtPointer(e) {
    setNdc(e);
    raycaster.setFromCamera(ndc, camera);
    const hits = raycaster.intersectObjects(lanes.map((l) => l.reviewHit));
    if (!hits.length) return null;
    const l = lanes[hits[0].object.userData.reviewLaneIdx];
    return l && l.state === "sealed" ? l : null;
  }
  function groundAt(e) {
    setNdc(e);
    raycaster.setFromCamera(ndc, camera);
    const p = new THREE.Vector3();
    return raycaster.ray.intersectPlane(groundPlane, p) ? p : null;
  }
  function nearestEmptyLane(p) {
    if (!p) return null;
    let best = null, bd = 1e9;
    for (const l of lanes) {
      if (l.state !== "empty") continue;
      const d = Math.abs(p.x - l.start.x);
      if (d < bd) { bd = d; best = l; }
    }
    return (best && bd < 6 && p.z < BAY_Z - 8) ? best : null;
  }

  // ---------- HUD helpers ----------
  function setPrompt(text) {
    if (!promptEl || text === promptText) return;
    promptText = text;
    if (text) { promptEl.textContent = text; promptEl.classList.remove("hidden"); }
    else promptEl.classList.add("hidden");
  }
  function showTutorial(text, ms = 5500) {
    if (!tutorialEl) return;
    clearTimeout(tutorialTimer);
    tutorialEl.textContent = text;
    tutorialEl.classList.remove("hidden");
    if (ms > 0) tutorialTimer = setTimeout(() => tutorialEl.classList.add("hidden"), ms);
  }
  function teachOnce(key, text, ms) {
    if (taught.has(key)) return;
    taught.add(key);
    showTutorial(text, ms);
  }
  function setControls() {
    if (!controlsEl) return;
    controlsEl.innerHTML = `
      <span class="control-item"><span class="control-label">Drag car to track</span><span class="key key-wide">drag</span></span>
      <span class="control-item"><span class="control-label">Launch loaded</span><span class="key">Space</span></span>
      <span class="control-item"><span class="control-label">Nitro · review</span><span class="key key-wide">click</span></span>
      <span class="control-item"><span class="control-label">Look around</span><span class="key key-wide">drag bg</span></span>
      <span class="control-item"><span class="control-label">Zoom</span><span class="key key-wide">scroll</span></span>
      <span class="control-item"><span class="control-label">Return to orbit</span><span class="key">B</span></span>
    `;
    controlsEl.classList.remove("hidden");
  }
  function hideControls() { controlsEl?.classList.add("hidden"); }

  // ---------- systems status panel (aggregate — twelve rows won't fit) ----------
  function updateSystems() {
    if (!systemsEl) return;
    const dots = Array.from({ length: NITRO_MAX }, (_, i) =>
      `<span class="db-nitro-dot${i < nitro ? "" : " is-spent"}"></span>`).join("");
    const online = addedCount();
    const enroute = lanes.filter((l) => l.state === "running").length;
    const review = lanes.filter((l) => l.state === "sealed").length;
    const bogged = lanes.filter((l) => l.state === "running" && l.stalled).length;
    const freeCars = cars.filter((c) => c.state === "bay").length;
    systemsEl.innerHTML =
      `<div class="db-nitro"><span class="db-nitro-label">NITRO</span><span class="db-nitro-dots">${dots}</span></div>` +
      `<div class="db-jobs"><span class="db-jobs-num">${online} / ${lanes.length}</span>` +
      `<span class="db-jobs-lbl">systems online</span></div>` +
      `<div class="db-tally">` +
        `<span class="db-tally-it is-running">en route ${enroute}</span>` +
        `<span class="db-tally-it is-sealed">to review ${review}</span>` +
        (bogged ? `<span class="db-tally-it is-stalled">bogged ${bogged}</span>` : ``) +
      `</div>` +
      `<div class="db-tally"><span class="db-tally-it is-cars">cars free ${freeCars} / ${N_CARS}</span></div>`;
  }

  // ---------- level countdown ----------
  function fmtTime(s) {
    s = Math.max(0, Math.ceil(s));
    return `${Math.floor(s / 60)}:${String(s % 60).padStart(2, "0")}`;
  }
  function updateClock() {
    if (countdownTime) countdownTime.textContent = fmtTime(timeLeft);
    countdownEl?.classList.toggle("is-low", timerRunning && timeLeft <= LOW_TIME);
    countdownEl?.classList.toggle("is-critical", timerRunning && timeLeft <= CRIT_TIME);
  }
  function panicFactor() {
    if (failed) return 1;
    if (!timerRunning || timeLeft > PANIC_TIME) return 0;
    let p = (PANIC_TIME - timeLeft) / PANIC_TIME;
    p *= p;
    if (timeLeft <= CRIT_TIME) {
      const throb = 0.5 + 0.5 * Math.sin(performance.now() / 85);
      p += 0.14 * throb;
    }
    return Math.min(1, p);
  }
  function applyPanicSky() {
    const p = reportSent ? 0 : panicFactor();
    scene.background.copy(SKY_CALM).lerp(SKY_PANIC, p);
    scene.fog.color.copy(SKY_CALM).lerp(FOG_PANIC, p);
    dome.material.color.copy(DOME_CALM).lerp(DOME_PANIC, p);
    sun.color.copy(SUN_CALM).lerp(SUN_PANIC, p * 0.85);
  }

  // ---------- briefing / win / fail / reset ----------
  function restartTextAnim(el) {
    if (!el) return;
    el.classList.remove("beat-in");
    void el.offsetWidth;
    el.classList.add("beat-in");
  }
  function renderBriefingBeat() {
    if (!briefingTextEl) return;
    briefingTextEl.textContent = BRIEFING_BEATS[briefingIndex] || "";
    restartTextAnim(briefingTextEl);
    if (briefingNextEl) briefingNextEl.textContent =
      briefingIndex < BRIEFING_BEATS.length - 1 ? "to continue" : "to begin";
  }
  function advanceBriefing() {
    if (started) return;
    if (briefingIndex < BRIEFING_BEATS.length - 1) {
      briefingIndex += 1;
      renderBriefingBeat();
      return;
    }
    startLevel();
  }
  function showBriefing() {
    timerRunning = false;
    tutorialEl?.classList.add("hidden");
    briefingIndex = 0;
    renderBriefingBeat();
    briefingEl?.classList.remove("hidden");
  }
  function startLevel() {
    if (started) return;
    started = true;
    briefingEl?.classList.add("hidden");
    timeLeft = TOTAL_TIME;
    timerRunning = false;
    clockStarted = false;
    updateClock();
    updateSystems();
    showTutorial("Drag cars onto tracks, then SPACE for the green flag. Twelve jobs, six cars — they come back when done, so keep them moving.", 9500);
  }
  briefingEl?.addEventListener("click", () => { if (active && !started) advanceBriefing(); });

  function failLevel() {
    if (failed || reportSent) return;
    failed = true;
    timerRunning = false;
    closeTerminal(false);
    countdownEl?.classList.remove("is-low", "is-critical");
    tutorialEl?.classList.add("hidden");
    failEl?.classList.remove("hidden");
  }
  function resetLevel() {
    failed = false;
    reportSent = false;
    reportDismissed = false;
    nitro = NITRO_MAX;
    clockStarted = false;
    clearTimeout(winTimer);
    for (const c of cars) {
      c.state = "bay";
      c.lane = null;
      c.mesh.position.copy(c.home);
      c.mesh.rotation.y = 0;
      c.mesh.userData.glow.material.opacity = 0;
    }
    for (const l of lanes) {
      l.carObj = null;
      l.state = "empty";
      l.prog = 0; l.boostT = 0; l.corrupt = 0; l.meltT = 0;
      l.stalled = false; l.hazardCleared = false;
      l.brokenModel.visible = true;
      l.upgradeModel.visible = false;
      const anim = l.upgradeModel.userData.anim;
      if (anim?.type === "spire") anim.beam.visible = false;
      l.ice.visible = false;
      l.ice.material.opacity = 0.62;
      l.sprite.visible = false;
      l.hzMesh.visible = true;
    }
    failEl?.classList.add("hidden");
    winEl?.classList.add("hidden");
    updateSystems();
    timeLeft = TOTAL_TIME;
    timerRunning = false;
    updateClock();
    showTutorial("New attempt — keep all six cars rolling.", 6000);
  }

  // ---------- drag: load a car onto a track ----------
  function beginDrag(car) {
    if (car.state === "loaded" && car.lane) {
      car.lane.carObj = null;
      car.lane.state = "empty";
      car.lane = null;
    }
    updateSystems();
  }
  function assignCar(car, lane) {
    car.state = "loaded";
    car.lane = lane;
    lane.carObj = car;
    lane.state = "loaded";
    lane.prog = 0; lane.corrupt = 0; lane.stalled = false; lane.hazardCleared = false;
    car.mesh.position.copy(lane.start);
    car.mesh.rotation.y = Math.atan2(-(lane.finish.x - lane.start.x), -(lane.finish.z - lane.start.z));
    teachOnce("loaded", "Loaded. Drop more cars on tracks, or press SPACE to send every loaded car at once.", 7000);
  }
  function returnHome(car) {
    car.state = "bay";
    car.lane = null;
    car.mesh.position.copy(car.home);
    car.mesh.rotation.y = 0;
  }

  // ---------- launch / boost ----------
  function greenFlag() {
    let launched = 0;
    for (const l of lanes) {
      if (l.state === "loaded" && l.carObj) {
        l.state = "running";
        l.carObj.state = "running";
        l.prog = 0; l.corrupt = 0; l.stalled = false; l.hazardCleared = false;
        launched++;
      }
    }
    if (!launched) return;
    if (!clockStarted) { clockStarted = true; timerRunning = true; }
    updateSystems();
    teachOnce("launched", "They're off. A car bogging down in a red patch? Click it to nitro through.", 8000);
  }
  function boost(l) {
    if (!l || l.state !== "running" || !l.carObj) return;
    if (nitro <= 0) { showTutorial("Out of nitro — that one rides it out.", 1800); return; }
    if (l.boostT > 0) return;
    nitro -= 1;
    l.boostT = BOOST_DUR;
    l.hazardCleared = true;
    l.corrupt = 0;
    l.stalled = false;
    spawnSpark(l.carObj.mesh.position.clone(), 0xffb86b, 18);
    updateSystems();
  }
  function sealSite(l) {
    l.state = "sealed";
    const car = l.carObj;
    l.carObj = null;
    l.brokenModel.visible = false;
    l.upgradeModel.visible = true;
    l.ice.visible = true;
    l.ice.material.opacity = 0.62;
    l.sprite.visible = true;
    spawnSpark(l.anchor.position.clone().setY(l.anchor.position.y + 3), 0x8fe3ff, 16);
    // The car detaches and drives itself back to the bay to be reused.
    if (car) {
      car.state = "returning";
      car.lane = null;
      car.retFrom = car.mesh.position.clone();
      car.retTo = car.home.clone();
      car.retProg = 0;
      car.mesh.userData.glow.material.opacity = 0;
    }
    updateSystems();
    if (allHome()) timerRunning = false;     // every job sealed — run survived
    teachOnce("sealed",
      "A job's done — sealed under a checkpoint (ice-blue), and the car heads home. Click the sealed job to see what the subagent did.", 8500);
  }

  // ---------- terminal ----------
  function flashTerminal(text, ok) {
    if (!termMsg) return;
    clearTimeout(msgTimer);
    termMsg.textContent = text;
    termMsg.classList.remove("show-ok", "show-err");
    termMsg.classList.add(ok ? "show-ok" : "show-err");
    msgTimer = setTimeout(() => termMsg.classList.remove("show-ok", "show-err"), 3600);
  }
  function renderTerminal() {
    if (!terminalOpen) return;
    if (termMode === "review") {
      if (!explained) {
        termHint.textContent = "# what did the subagent actually do? ask the checkpoint";
        termInput.textContent = `entire checkpoint explain ${reviewSite.data.ckpt}`;
        termInput.classList.remove("is-dim");
        if (termCta) termCta.innerHTML =
          `<span class="cta-label">PRESS</span>` +
          `<kbd class="cta-key cta-key-yes">Enter</kbd><span class="cta-note">run it</span>`;
      } else {
        termHint.textContent = "# reviewed — your call";
        termInput.textContent = `entire checkpoint explain ${reviewSite.data.ckpt}`;
        termInput.classList.add("is-dim");
        if (termCta) termCta.innerHTML =
          `<button id="db-add-btn" type="button">ADD TO SHIP</button>` +
          `<span class="cta-note">or press <kbd class="cta-key cta-key-yes">Y</kbd></span>`;
      }
    } else if (termMode === "report") {
      termHint.textContent = reportSent
        ? "# dispatch sent — the day is on the record"
        : "# twelve jobs accepted — send the day's report";
      termInput.textContent = buffer;
      termInput.classList.remove("is-dim");
      if (termCta) termCta.innerHTML = reportSent ? "" :
        `<span class="cta-label">TYPE</span><span class="cta-cmd">entire dispatch</span>`;
    }
  }
  function openTerminal(mode, site) {
    if (terminalOpen) return;
    terminalOpen = true;
    termMode = mode;
    reviewSite = site || null;
    explained = false;
    buffer = "";
    termMsg?.classList.remove("show-ok", "show-err");
    termList?.classList.add("hidden");
    termEl?.classList.remove("hidden");
    renderTerminal();
  }
  function closeTerminal(dismiss) {
    if (!terminalOpen) return;
    if (dismiss && termMode === "report") reportDismissed = true;
    terminalOpen = false;
    termMode = null;
    reviewSite = null;
    explained = false;
    buffer = "";
    termEl?.classList.add("hidden");
    termList?.classList.add("hidden");
  }

  // ---------- entire checkpoint explain ----------
  function runExplain() {
    if (!reviewSite || explained) return;
    explained = true;
    const s = reviewSite;
    if (termList) {
      termList.innerHTML =
        `<div class="term-list-row"><span class="tl-key tl-exp-key">checkpoint</span>` +
        `<span class="tl-title">${s.data.ckpt}</span></div>` +
        s.data.card.map(([k, v]) =>
          `<div class="term-list-row"><span class="tl-key tl-exp-key">${k}</span>` +
          `<span class="tl-title">${v}</span></div>`
        ).join("");
      termList.classList.remove("hidden");
    }
    flashTerminal(`explained ${s.data.ckpt} — ${s.data.name.toLowerCase()} is now a ${s.data.became}`, true);
    teachOnce("explained",
      "That's the story behind the checkpoint — work you didn't watch is never a mystery. If it's good, add it to the ship.", 8000);
    renderTerminal();
  }

  // ---------- ADD TO SHIP ----------
  function addToShip() {
    if (!reviewSite || !explained) return;
    const s = reviewSite;
    s.state = "added";
    s.meltT = MELT_DUR;
    const anim = s.upgradeModel.userData.anim;
    if (anim?.type === "spire") anim.beam.visible = true;
    updateSystems();
    if (allAdded()) {
      termMode = "report";
      reviewSite = null;
      explained = false;
      buffer = "";
      termList?.classList.add("hidden");
      flashTerminal("all twelve systems online", true);
      showTutorial("Every system accounted for — send the day's report: type `entire dispatch`.", 0);
      renderTerminal();
    } else {
      closeTerminal(false);
      showTutorial(`${s.data.name} online (${addedCount()} / ${lanes.length}).`, 4000);
    }
  }
  termCta?.addEventListener("click", (e) => {
    if (!active) return;
    if (e.target?.id === "db-add-btn") addToShip();
  });

  // ---------- the finish line: entire dispatch ----------
  function sendDispatch() {
    reportSent = true;
    timerRunning = false;
    countdownEl?.classList.remove("is-low", "is-critical");
    if (termList) {
      termList.innerHTML =
        `<div class="term-list-row"><span class="tl-key tl-exp-key">DISPATCH</span>` +
        `<span class="tl-title">drone bay — day report</span></div>` +
        lanes.map((l) =>
          `<div class="term-list-row"><span class="tl-key tl-exp-key">·</span>` +
          `<span class="tl-title">${l.data.name.toLowerCase()} → ${l.data.became} (${l.data.ckpt.slice(0, 6)}…)</span></div>`
        ).join("") +
        `<div class="term-list-row"><span class="tl-key tl-exp-key">filed</span>` +
        `<span class="tl-title">from 12 checkpoints · crew: 1 human, 6 subagents</span></div>`;
      termList.classList.remove("hidden");
    }
    flashTerminal("dispatch sent — look how much got done without you", true);
    renderTerminal();
    if (winSub) winSub.textContent = "twelve jobs, six cars — the report wrote itself";
    winTimer = setTimeout(() => {
      closeTerminal(false);
      tutorialEl?.classList.add("hidden");
      winEl?.classList.remove("hidden");
    }, 4000);
    onComplete?.();
  }
  function submitCommand() {
    const n = normalizeCmd(buffer);
    buffer = "";
    if (!n) { renderTerminal(); return; }
    if (/^entire dispatch$/.test(n)) { sendDispatch(); return; }
    if (/^entire (checkpoint|cp) list$/.test(n)) {
      if (termList) {
        termList.innerHTML = lanes.map((l) =>
          `<div class="term-list-row"><span class="tl-id tl-id-short">${l.data.ckpt}</span>` +
          `<span class="tl-title">subagent fix: ${l.data.name.toLowerCase()} → ${l.data.became}</span></div>`
        ).join("");
        termList.classList.remove("hidden");
      }
      flashTerminal("the raw log — now turn it into the day's report:  entire dispatch", true);
      renderTerminal();
      return;
    }
    flashTerminal("command not recognized — try:  entire dispatch", false);
    renderTerminal();
  }

  // ---------- input ----------
  function onPointerDown(e) {
    if (!active || !started || failed || reportSent || terminalOpen) return;
    pointerDown = true;
    dragging = false;
    dropTarget = null;
    downX = e.clientX; downY = e.clientY; lastX = e.clientX; lastY = e.clientY;
    const c = carAtPointer(e);
    if (c) { picked = c; pickedKind = "car"; pickedDraggable = (c.state === "bay" || c.state === "loaded"); return; }
    const j = jobAtPointer(e);
    if (j) { pickedJob = j; pickedKind = "job"; return; }
    pickedKind = "camera";
  }
  function onPointerMove(e) {
    if (!active || !started || failed || terminalOpen) { canvas.style.cursor = "default"; return; }

    if (pointerDown && pickedKind === "car" && pickedDraggable) {
      if (!dragging) {
        if (Math.hypot(e.clientX - downX, e.clientY - downY) > 5) { dragging = true; beginDrag(picked); }
      }
      if (dragging) {
        const p = groundAt(e);
        if (p) picked.mesh.position.set(p.x, terrain.heightAt(p.x, p.z) + 2.0, p.z);
        dropTarget = nearestEmptyLane(p);
        canvas.style.cursor = "grabbing";
      }
      return;
    }
    if (pointerDown && pickedKind === "camera") {
      const dx = e.clientX - lastX, dy = e.clientY - lastY;
      camTheta = clamp(camTheta - dx * 0.005, -0.9, 0.9);
      camPhi = clamp(camPhi - dy * 0.005, 0.5, 1.45);
      lastX = e.clientX; lastY = e.clientY;
      canvas.style.cursor = "grabbing";
      return;
    }

    // plain hover
    const c = carAtPointer(e);
    if (c) {
      hoverCar = c;
      canvas.style.cursor = (c.state === "bay" || c.state === "loaded") ? "grab" : (c.state === "running" ? "pointer" : "default");
      return;
    }
    hoverCar = null;
    canvas.style.cursor = jobAtPointer(e) ? "pointer" : "grab";
  }
  function onPointerUp(e) {
    if (!pointerDown) return;
    pointerDown = false;
    const moved = Math.hypot(e.clientX - downX, e.clientY - downY);
    if (pickedKind === "car" && picked) {
      if (dragging) {
        const p = groundAt(e);
        const lane = nearestEmptyLane(p);
        if (lane) assignCar(picked, lane);
        else returnHome(picked);
      } else if (picked.state === "running") {
        boost(picked.lane);
      }
    } else if (pickedKind === "job" && pickedJob && moved < 6) {
      if (pickedJob.state === "sealed") openTerminal("review", pickedJob);
    }
    picked = null; pickedJob = null; pickedKind = null; dragging = false; dropTarget = null;
    updateSystems();
    canvas.style.cursor = "default";
  }
  function onWheel(e) {
    if (!active || !started || terminalOpen) return;
    e.preventDefault();
    camRadius = clamp(camRadius * (1 + e.deltaY * 0.001), 56, 210);
  }
  function onKeyDown(e) {
    if (!active) return;

    if (!started) {
      if (e.code === "Enter" || e.code === "Space") { advanceBriefing(); e.preventDefault(); }
      return;
    }
    if (failed) {
      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
      if (e.code === "KeyN") { onNewGame?.(); e.preventDefault(); }
      return;
    }
    if (terminalOpen) {
      if (e.code === "Escape") { closeTerminal(true); e.preventDefault(); return; }
      if (termMode === "review") {
        if (!explained && e.code === "Enter") { runExplain(); e.preventDefault(); return; }
        if (explained && (e.key === "y" || e.key === "Y")) { addToShip(); e.preventDefault(); return; }
        e.preventDefault();
        return;
      }
      if (reportSent) { e.preventDefault(); return; }
      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
        buffer += e.key; renderTerminal(); e.preventDefault();
      }
      return;
    }

    if (reportSent && e.code === "Enter") { onNext?.(); e.preventDefault(); return; }
    if (e.code === "Space") { greenFlag(); e.preventDefault(); return; }
    if (e.code === "Enter" && allAdded() && !reportSent) {
      reportDismissed = false; openTerminal("report", null); e.preventDefault(); return;
    }
    if (e.code === "KeyB") { onExit?.(); e.preventDefault(); }
  }

  // ---------- HUD per-frame ----------
  function refreshHud() {
    if (!started || terminalOpen) { setPrompt(null); return; }
    if (reportSent) { setPrompt("The day is dispatched — press Enter to board the ship"); return; }
    if (allAdded()) { setPrompt("All systems online — press Enter to send the day's report: `entire dispatch`"); return; }
    if (anyRunning()) {
      setPrompt(`Cars en route — click a bogged one to nitro it (${nitro} left)`);
      return;
    }
    if (anySealed()) {
      setPrompt("Finished jobs are stacking up — click an ice-blue one to review it");
      return;
    }
    if (loadedCount() > 0) {
      setPrompt(`${loadedCount()} loaded — press SPACE for the green flag, or drag in more`);
      return;
    }
    if (openTracks() && carsFree()) {
      setPrompt("Drag a subagent car onto an open track");
      return;
    }
    setPrompt("Drag a car onto a track");
  }

  // ---------- per-frame ----------
  function update(dt, t) {
    if (active && timerRunning && !failed && !reportSent) {
      timeLeft = Math.max(0, timeLeft - dt);
      updateClock();
      if (timeLeft <= 0) failLevel();
    }
    applyPanicSky();
    updateCamera();

    // Cars: bay idle, returning drive home.
    for (const c of cars) {
      if (c === picked && dragging) continue;
      if (c.state === "bay") {
        c.mesh.position.y = c.home.y + Math.sin((t + c.idx) * 2) * 0.05;
        c.mesh.userData.bodyMat.emissiveIntensity = 0.4;
        c.mesh.userData.cabin.material.emissiveIntensity = 0.45;
      } else if (c.state === "returning") {
        c.retProg = Math.min(1, c.retProg + BASE_SPEED * RETURN_MULT * dt);
        const k = c.retProg;
        const x = c.retFrom.x + (c.retTo.x - c.retFrom.x) * k;
        const z = c.retFrom.z + (c.retTo.z - c.retFrom.z) * k;
        c.mesh.position.set(x, terrain.heightAt(x, z) + 0.6, z);
        c.mesh.rotation.y = Math.atan2(-(c.retTo.x - c.retFrom.x), -(c.retTo.z - c.retFrom.z));
        for (const w of c.mesh.userData.wheels) w.rotation.x += 10 * dt;
        c.mesh.userData.bodyMat.emissiveIntensity = 0.5;
        if (c.retProg >= 1) {
          c.state = "bay";
          c.mesh.position.copy(c.home);
          c.mesh.rotation.y = 0;
          updateSystems();
          teachOnce("reuse", "That car's free again — drag it onto another open track.", 6000);
        }
      }
    }

    // Lanes: loaded idle at the line; running drive their track.
    for (const l of lanes) {
      if (l.state === "loaded" && l.carObj) {
        const car = l.carObj.mesh;
        car.position.y = l.start.y + Math.sin((t + l.idx) * 2) * 0.05;
        const pulse = 0.55 + 0.45 * (0.5 + 0.5 * Math.sin(t * 6));
        car.userData.bodyMat.emissiveIntensity = pulse;
        car.userData.cabin.material.emissiveIntensity = pulse;
      } else if (l.state === "running" && l.carObj) {
        const car = l.carObj.mesh;
        if (l.boostT > 0) l.boostT = Math.max(0, l.boostT - dt);
        const hz = l.hazard;
        const inHaz = !l.hazardCleared && l.prog >= hz.at && l.prog <= hz.at + hz.len;

        if (inHaz && hz.severe && l.boostT <= 0) {
          l.corrupt = Math.min(1, l.corrupt + dt / HAZARD_FILL);
          if (l.corrupt >= 1 && !l.stalled) {
            l.stalled = true;
            updateSystems();
            teachOnce("stall", "A car bogged down in a corruption patch — click it to spend a nitro and break it free.", 7000);
          }
        }

        let mult = 1;
        if (l.boostT > 0) mult = BOOST_MULT;
        else if (inHaz) mult = l.stalled ? STALL_CRAWL : HAZARD_SLOW;

        l.prog = Math.min(1, l.prog + BASE_SPEED * mult * dt);
        const k = l.prog;
        const x = l.start.x + (l.finish.x - l.start.x) * k;
        const z = l.start.z + (l.finish.z - l.start.z) * k;
        car.position.set(x, terrain.heightAt(x, z) + 0.6, z);

        const boosting = l.boostT > 0;
        const spin = (boosting ? 18 : mult < 0.5 ? 2 : 7) * dt;
        for (const w of car.userData.wheels) w.rotation.x += spin;
        car.userData.glow.material.opacity = boosting ? 0.55 + 0.25 * Math.sin(t * 30) : 0;
        car.userData.bodyMat.emissiveIntensity = boosting ? 1.4 : l.stalled ? 0.3 : 0.7;
        if (boosting && Math.random() < dt * 12) {
          spawnSpark(car.position.clone().setY(car.position.y + 0.4), 0xffb86b, 4);
        }
        if (l.prog >= 1) sealSite(l);
      }
    }

    if (hoverCar && !dragging) {
      const c = hoverCar;
      if (c.state === "bay" || c.state === "loaded" || c.state === "running") {
        c.mesh.userData.cabin.material.emissiveIntensity = 1.1;
      }
    }

    // Corruption patches.
    for (const l of lanes) {
      const hm = l.hzMesh, ud = hm.userData;
      if (!hm.visible) continue;
      if (l.state === "added" || l.hazardCleared) {
        ud.shardMat.emissiveIntensity = Math.max(0, ud.shardMat.emissiveIntensity - dt * 1.6);
        ud.domeMat.opacity = Math.max(0, ud.domeMat.opacity - dt * 0.4);
        ud.ringMat.opacity = Math.max(0.05, ud.ringMat.opacity - dt * 0.6);
        ud.shardMat.color.lerp(new THREE.Color(0x123a4a), 0.05);
        if (ud.shardMat.emissiveIntensity < 0.05) hm.visible = false;
      } else {
        const hot = l.state === "running" && (l.stalled || l.corrupt > 0);
        ud.shardMat.emissiveIntensity = 1.2 + Math.sin(t * 4 + l.idx) * 0.3 + (hot ? 0.8 : 0);
        ud.domeMat.opacity = (ud.severe ? 0.2 : 0.14) + (hot ? 0.12 : 0);
        hm.rotation.y += dt * (hot ? 1.2 : 0.3);
      }
    }

    // Drop-target highlight.
    for (const l of lanes) {
      l.railMat.color.setHex(l === dropTarget ? 0x6fe3ff : 0x35506a);
      l.railMat.opacity = l === dropTarget ? 0.95 : 0.6;
    }

    // Status beams + warnings + seals + live upgrades.
    for (const l of lanes) {
      if (l.state === "empty" || l.state === "loaded") {
        l.beam.material.color.setHex(l.state === "loaded" ? 0x6fe3ff : 0xff8a5c);
        l.beam.material.opacity = 0.28 + Math.sin(t * 1.6 + l.idx) * 0.08;
        l.beam.visible = true;
        const warn = l.brokenModel.userData.warn;
        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + l.idx) > 0 ? 1.8 : 0.2;
      } else if (l.state === "running") {
        l.beam.material.color.setHex(l.stalled ? 0xff5a3c : 0x6fe3ff);
        l.beam.material.opacity = 0.42 + Math.sin(t * 6) * 0.18;
        l.beam.visible = true;
        const warn = l.brokenModel.userData.warn;
        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + l.idx) > 0 ? 1.8 : 0.2;
      } else if (l.state === "sealed") {
        l.beam.material.color.setHex(0x8fe3ff);
        l.beam.material.opacity = 0.46;
        l.beam.visible = true;
      } else {
        l.beam.visible = false;
        if (l.meltT > 0) {
          l.meltT = Math.max(0, l.meltT - dt);
          l.ice.material.opacity = 0.62 * (l.meltT / MELT_DUR);
          if (l.meltT <= 0) l.ice.visible = false;
        }
        const anim = l.upgradeModel.userData.anim;
        if (anim?.type === "ring") {
          anim.ring.rotation.y += dt * 0.8;
          anim.ring.position.y = 3.4 + Math.sin(t * 1.6) * 0.2;
        } else if (anim?.type === "dome") {
          anim.field.rotation.y += dt * 0.25;
          anim.orbit.rotation.z += dt * 0.6;
        } else if (anim?.type === "skid") {
          anim.pad.position.y = 1.6 + Math.sin(t * 1.8) * 0.25;
        }
      }
    }

    // Spark bursts.
    for (let i = sparks.length - 1; i >= 0; i--) {
      const s = sparks[i];
      s.life += dt;
      const pos = s.geo.attributes.position.array;
      for (let j = 0; j < s.vel.length; j++) {
        s.vel[j].y -= 14 * dt;
        pos[j * 3] += s.vel[j].x * dt;
        pos[j * 3 + 1] += s.vel[j].y * dt;
        pos[j * 3 + 2] += s.vel[j].z * dt;
      }
      s.geo.attributes.position.needsUpdate = true;
      s.mat.opacity = Math.max(0, 1 - s.life / s.ttl);
      if (s.life >= s.ttl) {
        scene.remove(s.pts);
        s.geo.dispose(); s.mat.dispose();
        sparks.splice(i, 1);
      }
    }

    consoleGlow.intensity = allAdded() && !reportSent ? 8 + Math.sin(t * 4) * 3 : 5;

    if (active && started && !failed) {
      if (!terminalOpen && allAdded() && !reportSent && !reportDismissed) {
        openTerminal("report", null);
      }
    }

    if (active) refreshHud();
  }

  // ---------- lifecycle ----------
  function enter() {
    active = true;
    camTarget.set(0, 0, 14);
    camRadius = 124; camTheta = 0; camPhi = 1.2;
    updateCamera();
    canvas.addEventListener("mousedown", onPointerDown);
    canvas.addEventListener("mousemove", onPointerMove);
    canvas.addEventListener("wheel", onWheel, { passive: false });
    window.addEventListener("mouseup", onPointerUp);
    window.addEventListener("keydown", onKeyDown);
    dbHud?.classList.remove("hidden");
    fpShared?.classList.remove("hidden");
    crosshair?.classList.add("hidden");
    setControls();
    updateSystems();
    if (!started) {
      showBriefing();
    } else if (reportSent) {
      winEl?.classList.remove("hidden");
    } else if (failed) {
      resetLevel();
    } else {
      timerRunning = clockStarted && !allHome();
      showTutorial("The cars kept rolling while you were in orbit.", 5000);
    }
    updateClock();
    applyPanicSky();
  }
  function exit() {
    active = false;
    timerRunning = false;
    closeTerminal(false);
    clearTimeout(winTimer);
    canvas.removeEventListener("mousedown", onPointerDown);
    canvas.removeEventListener("mousemove", onPointerMove);
    canvas.removeEventListener("wheel", onWheel);
    window.removeEventListener("mouseup", onPointerUp);
    window.removeEventListener("keydown", onKeyDown);
    canvas.style.cursor = "default";
    setPrompt(null);
    hideControls();
    tutorialEl?.classList.add("hidden");
    termEl?.classList.add("hidden");
    failEl?.classList.add("hidden");
    winEl?.classList.add("hidden");
    briefingEl?.classList.add("hidden");
    dbHud?.classList.add("hidden");
    fpShared?.classList.add("hidden");
    crosshair?.classList.add("hidden");
  }
  function resize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
  }

  return {
    scene,
    get camera() { return camera; },
    update, enter, exit, resize,
  };
}

