import { createTerrain } from "/Users/goose-guest/Documents/work/planetfall-seed-signalkit/src/terrain.js";
const t = createTerrain({ size:200, segments:220, maxHeight:26, seed:1337 });
const N=12, N_CARS=6;

function test(label, START_Z, FINISH_Z, DOCK_X, DOCK_Z0, DOCK_DZ){
  const LANE=(i,n)=>({startX:(i-(n-1)/2)*6, finishX:(i-(n-1)/2)*7});
  let minFin=1e9,minTrack=1e9,minStart=1e9,minDock=1e9,wT=null;
  for(let i=0;i<N;i++){const {startX,finishX}=LANE(i,N);
    minFin=Math.min(minFin,t.heightAt(finishX,FINISH_Z));
    minStart=Math.min(minStart,t.heightAt(startX,START_Z));
    for(let k=0;k<=8;k++){const kk=k/8;const h=t.heightAt(startX+(finishX-startX)*kk,START_Z+(FINISH_Z-START_Z)*kk);if(h<minTrack){minTrack=h;wT=`@${kk.toFixed(2)}`;}}}
  for(let i=0;i<N_CARS;i++){minDock=Math.min(minDock,t.heightAt(DOCK_X,DOCK_Z0+i*DOCK_DZ));}
  const ok=Math.min(minFin,minTrack,minStart,minDock)>1.3;
  console.log(`${ok?"OK ":"WET"} ${label}: beam=${minFin.toFixed(1)} start=${minStart.toFixed(1)} track=${minTrack.toFixed(1)}${wT} dock=${minDock.toFixed(1)}`);
}
